INSERT INTO public.questions VALUES ('1339c3fd-1cec-4d7b-89a3-1c6834b8b607', '2a163e2c-1df6-4821-9bfd-95092873837e', 'matching', 'Questions 11-17', '', '<p dir="ltr">Label the map below.</p>
<p dir="ltr">Choose <strong>SEVEN</strong> answers from the box and write the correct letter, <strong>A-H</strong>,next to questions 11-17</p>
<p> </p>', 'matching_name', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p> </p>\n<table style=\"border-collapse: collapse; width: 89.6801%;\" border=\"1\"><colgroup><col style=\"width: 97.7636%;\"><col style=\"width: 2.25484%;\"></colgroup>\n<tbody>\n<tr>\n<td><img src=\"data:image/png;base64,\" width=\"593\" height=\"335\"></td>\n<td>\n<p>{F Local Heroes}</p>\n<p> </p>\n<p>{H Recent Award Winners}</p>\n<p> </p>\n<p>{E Learning Zone}</p>\n<p> </p>\n<p>{G Members'' Restaurant}</p>\n<p> </p>\n<p>{C Gallery Shop}</p>\n<p> </p>\n<p>{D History in Photographs}</p>\n<p> </p>\n<p>{A Cinema Zone}</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p> </p>", "answerOptions": [{"optionText": "A Cinema Zone"}, {"optionText": "B European Paintings"}, {"optionText": "C Gallery Shop"}, {"optionText": "D History in Photographs"}, {"optionText": "E Learning Zone"}, {"optionText": "F Local Heroes"}, {"optionText": "G Members'' Restaurant"}, {"optionText": "H Recent Award Winners"}], "matchingItems": [{"questionPart": "11", "correctAnswer": "F"}, {"questionPart": "12", "correctAnswer": "H"}, {"questionPart": "13", "correctAnswer": "E"}, {"questionPart": "14", "correctAnswer": "G"}, {"questionPart": "15", "correctAnswer": "C"}, {"questionPart": "16", "correctAnswer": "D"}, {"questionPart": "17", "correctAnswer": "A"}]}', 'null', '[{"content": "<h3 data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">PART 2: MODERN ART GALLERY TOUR</strong></h3>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Guide:</strong> Welcome to the Modern Art Gallery. It is my pleasure to introduce you to the various sections of the gallery. The gallery consists of two levels. As you can see from the map, we are in the large atrium on level 1 at the meeting point.</p>\n<p data-path-to-node=\"5\">First of all, I''ll tell you about the exhibits on this level. In this room <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"75\">(Q11)</strong></span>, you will find an exhibition of our very own <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"126\">Local Heroes (F)</strong></span>, told in photographs, paintings and memorabilia. This is a great starting point if you want to find out more about the people who have played an important role in our city.</p>\n<p data-path-to-node=\"6\">Between the ticket booth and lifts, you''ll find the entrance to the other major display on this level <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"102\">(Q12)</strong></span>. All the works featured here are by <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"144\">Recent Award Winners (H)</strong></span>—modern artists who have won awards in the last few years. Recent winners such as Martelli and Kashiwagi are on display, and I suggest you take advantage of it while it''s here.</p>\n<p data-path-to-node=\"7\">If you like sculpture, then please visit our section called Latin America. In the far corner, there''s an excellent collection of two of Columbia''s finest: sculptures by Morales and Alvarez are really not to be missed.</p>\n<p data-path-to-node=\"8\">One of my favourite areas on the first level is for our younger visitors. The resident art teacher is here throughout the school holidays to help your children create a piece of art in the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"189\">(Q13) Learning Zone (E)</strong></span>. You''ll find it between the Latin American exhibition and the cafe.</p>\n<p data-path-to-node=\"9\">On the right here you''ll find the Gallery Cafe, which serves drinks and light meals throughout the day. If you have membership at any of the galleries or museums in the city, you can make use of the section reserved for members just next door <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"243\">(Q14)</strong></span>, our <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"254\">Members'' Restaurant (G)</strong></span>, which has views of the lake and an excellent menu.</p>\n<p data-path-to-node=\"10\">Before you make your way to the second level, you might like to take a look at the books and prints on sale in the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"115\">(Q15) Gallery Shop (C)</strong></span>, located next to the information desk. Gift certificates and membership packages can be bought there.</p>\n<p data-path-to-node=\"11\">Now let me introduce the second level of the gallery. As you step out of the lifts, you come into the largest exhibition in the gallery <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"136\">(Q16)</strong></span>. From World War 1 to the present day, this exhibition, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"197\">History in Photographs (D)</strong></span>, shows how photographers have responded to some of the most important local and global events in history.</p>\n<p data-path-to-node=\"12\">On the other side of the lifts is another permanent exhibition called Asia Today. Divided by region, you will experience work from the best Asian artists. And last but not least is one of the most innovative areas of the gallery <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"229\">(Q17)</strong></span>: our permanent <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"250\">Cinema Zone (A)</strong></span>. This cinema has two theatres showing films every two hours throughout the day.This month, we feature European filmmakers in the genre of animation from the millennium year to the present day.</p>\n<hr data-path-to-node=\"13\">\n<h3 data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">MUSEUM PASSES (Questions 18–20)</strong></h3>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Guide:</strong> If you have a full day to spend, there are several excellent museums in the city. In the same complex as this gallery, you''ll find the Natural History Museum, which has an excellent collection of gemstones. For those of you with children though, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"205\">(Q18) the best option is the recently upgraded Science Centre (A)</strong></span>, just next door to the Maritime Museum on the quayside.</p>\n<p data-path-to-node=\"16\">If you are here with the family and you do intend to visit more than one museum, I definitely recommend purchasing the Family Pass, as this will work out much cheaper and is a really good deal. You can visit two museums in one day, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"170\">(Q19) providing there is an adult in the group with between two and four children under sixteen (B - one adult and two children)</strong></span>.</p>\n<p data-path-to-node=\"17\">If you were here for a week or so and you would like to visit several museums or galleries, you might consider the Culture Pass. This allows unlimited entry for two adults to all galleries for <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"17\" data-index-in-node=\"193\">(Q20) three days (B)</strong></span>.</p>\n<p>You will save a lot by doing this, and you could revisit any of the galleries if you like. It''s also really good value as it covers travel on the routes between the museums on weekdays as well as the entry fee, so you save on transport too.</p>\n<p>We hope you enjoy your visit today and continue to support us. If you have any questions...</p>"}]', 0);
INSERT INTO public.questions VALUES ('f2e55381-f74b-49a0-acae-f2909ef971e9', 'c724d599-118b-4642-8e05-263fd611e640', 'fillup', 'Questions 31-40', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><span style="font-size: 12pt;"><strong>Autonomous Underwater Vehicle (A.U.V.)</strong></span></p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><strong>Description</strong></p>
<ul>
<li>
<p>looks like a small {aeroplane}</p>
</li>
<li>
<p>acts like a {robot}</p>
</li>
</ul>
<p><strong>Functions?</strong></p>
<ul>
<li>
<p>Can be used to measure:</p>
<ul>
<li>
<p>water pressure</p>
</li>
<li>
<p>level of {salt} in water</p>
</li>
<li>
<p>water temperature</p>
</li>
<li>
<p>water {quality}</p>
</li>
</ul>
</li>
<li>
<p>Measurements are used to help us understand:</p>
<ul>
<li>
<p>ocean behaves</p>
</li>
<li>
<p>the impact the ocean has on the {climate}</p>
</li>
</ul>
</li>
</ul>
<p><strong>The benefits?</strong></p>
<ul>
<li>
<p>easy to launch</p>
</li>
<li>
<p>isn’t connected to a boat by {cables}</p>
</li>
</ul>
<p><strong>What are the disadvantages?</strong></p>
<ul>
<li>
<p>not fast-moving</p>
</li>
<li>
<p>can’t be used to assess {chemical} levels in water</p>
</li>
</ul>
<p><strong>How does the A.U.V. work?</strong></p>
<ul>
<li>
<p>{oil} is pumped between two bladders.</p>
</li>
<li>
<p>It measures and records data as it moves to the {surface}</p>
</li>
<li>
<p>It sends the data from an antenna in the {right} wing-tip.</p>
</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 4: AUTONOMOUS UNDERWATER VEHICLE (A.U.V.)</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> Welcome class to your final lecture today. We are looking at the Autonomous Underwater Vehicle, or A.U.V.</p>\n<p data-path-to-node=\"4\">It actually resembles a miniature <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"4\" data-index-in-node=\"34\">(31) aeroplane</strong></span> that moves deep in the ocean. It’s not large enough to have a human crew aboard, and so its behavior is really that of a <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"4\" data-index-in-node=\"170\">(32) robot</strong>.</span></p>\n<p data-path-to-node=\"5\">The A.U.V. is programmed to calculate and record a range of data, depending on the mission it is carrying out at any one time. On previous missions, it has been programmed to record water pressure as well as how much <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"5\" data-index-in-node=\"217\">(33) salt</strong> </span>there is in the water.</p>\n<p data-path-to-node=\"6\">On a more recent mission around Bermuda, an A.U.V. was equipped with a special instrument that showed the temperature of the ocean at different depths. It can also assess the <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"6\" data-index-in-node=\"175\">(34) quality</strong></span> of the water in general.</p>\n<p data-path-to-node=\"7\">So as you see, it is quite a versatile and useful little piece of equipment. We use its measurements to determine and increase our understanding of ocean behaviors, as well as its role in and influence on our <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"7\" data-index-in-node=\"209\">(35) climate</strong>.</span></p>\n<hr data-path-to-node=\"8\">\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Lecturer:</strong> This instrument also has many other benefits. It can be launched and used relatively quickly. Also, there’s no need for <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"9\" data-index-in-node=\"130\">(36) cables</strong></span> to physically link it to a boat.</p>\n<p data-path-to-node=\"10\">There are disadvantages though. A.U.V.s move at only modest speeds, up to 25 cm per second. In addition, the A.U.V. structure cannot collect water samples, so other equipment must be used to conduct a <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"10\" data-index-in-node=\"201\">(37) chemical</strong></span> analysis of the water.</p>\n<hr data-path-to-node=\"11\">\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Lecturer:</strong> Now I’m sure you’re all wondering how the A.U.V. actually works. First, let’s see how an A.U.V. actually moves.</p>\n<p data-path-to-node=\"13\">It moves by pumping <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"13\" data-index-in-node=\"20\">(38) oil</strong></span> between two bladders. This helps the A.U.V. to sink or float.</p>\n<p data-path-to-node=\"14\">The A.U.V. records the data and measurements that it has been programmed to take while it rises to the <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"14\" data-index-in-node=\"103\">(39) surface</strong>.</span></p>\n<p data-path-to-node=\"15\">At the beginning and end of each dive, it obtains records and transmits its position by exposing an antenna embedded within the tip of the <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"15\" data-index-in-node=\"139\">(40) right</strong> </span>wing.</p>\n<p data-path-to-node=\"16\">Okay, so that’s the A.U.V.</p>"}]', 0);
INSERT INTO public.questions VALUES ('1bb8eb42-5ccf-4cc1-bdb5-42490b27a5dc', '26ad91ac-52c8-45ba-b987-33fee2dbccc4', 'fillup', 'Questions 1-7', '<p class="MsoNormal" style="margin: 0in 7.05pt 8.0pt 0in;"><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">Complete the notes below.</span></p>
<p class="MsoNormal" style="margin: 0in 7.05pt 8.0pt 0in;"><em><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</span></em></p>
<p style="text-align: center;"><strong><span style="font-size: 14.0pt; font-family: ''Arial'',sans-serif;">Pest control</span></strong></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">Early 20th-century problems in Australia</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>The larvae of a type of {beetle} were a serious pest in sugar cane fields.</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>Its larvae ate the {roots}<span style="mso-spacerun: yes;">  </span>of the plant.</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>Chemical pesticides were unsatisfactory because they were:</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">–<span style="mso-tab-count: 1;">        </span>poisonous</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">–<span style="mso-tab-count: 1;">        {expensive}</span></span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">–<span style="mso-tab-count: 1;">        </span>difficult to remove from the ground</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">Experiences with biological pest control</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>The use of insects, plants and birds was widespread.</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>In the 19th century French {gardeners}<span style="mso-spacerun: yes;"> </span>used toads.</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>In Australia a {moth}<span style="mso-spacerun: yes;">  </span>stopped the spread of prickly-pear cactus.</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>Cane toads were brought to Australia from {Hawaii}</span></p>
<p><span style="font-size: 11.0pt; font-family: ''Arial'',sans-serif;">•<span style="mso-tab-count: 1;">      </span>Cane toads proved to be a {failure} as pest control.</span></p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>1. Đáp án: beetle</strong></p>\n<ul data-path-to-node=\"3\">\n<li><strong>Dẫn chứng:</strong> “This was a species of <strong>beetle</strong> whose larvae, the infant form of the beetle, live underground…”</li>\n<li><strong>Giải thích:</strong> Bài đọc xác định đối tượng gây hại chính ở các cánh đồng mía là một loài bọ cánh cứng (beetle). Ấu trùng của loài bọ này mới là tác nhân trực tiếp phá hoại cây trồng.</li>\n</ul>\n<p><strong>2. Đáp án: roots</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong>Dẫn chứng:</strong> “The sugar cane plants were weakened or died because their <strong>roots</strong> were eaten by the larvae.”</li>\n<li><strong>Giải thích:</strong> Ấu trùng của bọ cánh cứng sống trong đất và ăn phần rễ (roots) của cây mía, khiến cây bị yếu đi hoặc chết, gây thiệt hại kinh tế.</li>\n</ul>\n<p><strong>3. Đáp án: expensive</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong>Dẫn chứng:</strong> “Chemicals like arsenic and copper were used, but these were not only <strong>expensive</strong> but also stayed in the environment…”</li>\n<li><strong>Giải thích:</strong> Các hóa chất diệt khuẩn thời kỳ đầu không được ưa chuộng vì chúng vừa tốn kém (expensive), vừa có độc tính tồn tại lâu dài trong môi trường.</li>\n</ul>\n<p><strong>4. Đáp án: gardeners</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong>Dẫn chứng:</strong> “…in 19th-century France toads were sold to <strong>gardeners</strong> at markets in Paris to eat insect pests in their gardens.”</li>\n<li><strong>Giải thích:</strong> Tại Pháp vào thế kỷ 19, những người làm vườn (gardeners) là nhóm đối tượng sử dụng cóc như một phương pháp diệt côn trùng tự nhiên trong khu vườn của họ.</li>\n</ul>\n<p><strong>5. Đáp án: moth</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong>Dẫn chứng:</strong> “…prevention of the increase of the exotic prickly-pear cactus by the introduction of a <strong>moth</strong> from Argentina.”</li>\n<li><strong>Giải thích:</strong> Tác giả đưa ra ví dụ về sự thành công của kiểm soát sinh học tại Úc khi sử dụng một loài bướm đêm (moth) để tiêu diệt cây xương rồng lê gai xâm lấn.</li>\n</ul>\n<p><strong>6. Đáp án: Hawaii</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong>Dẫn chứng:</strong> “…an Australian entomologist brought 101 cane toads from <strong>Hawaii</strong> and released them…”</li>\n<li><strong>Giải thích:</strong> Hawaii là địa điểm cụ thể mà các nhà khoa học đã thu thập 101 con cóc mía đầu tiên để mang về thả tại các đồn điền phía Bắc nước Úc.</li>\n</ul>\n<p><strong>7. Đáp án: failure</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong>Dẫn chứng:</strong> “…over the following years it became clear that the cane toads were a <strong>failure</strong>.”</li>\n<li><strong>Giải thích:</strong> Kế hoạch sử dụng cóc mía đã được chứng minh là một thất bại (failure) vì cóc sống trên mặt đất không thể ăn được ấu trùng bọ cánh cứng vốn sống sâu dưới rễ cây.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('bbe8342d-4bb6-43db-bcfa-ca941d514933', '35f2dfdf-25f4-48ec-83cc-f45c4bda102c', 'fillup', 'Questions 21–30', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write <strong>NO MORE THAN THREE WORDS AND/OR A NUMBER</strong> for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p><span style="font-size: 14pt;"><strong>Possible Course Change</strong></span></p>
<p>Name of student:                Sally Layman</p>
<p>Current course:                 {Economic History}</p>
<p>Date started:                      <span class="fill-history-correct">{last September}</span></p>
<p>Courses interested in: 1st choice  {Politics}</p>
<p>2nd choice  {Philosophy}</p>
<div dir="ltr" align="left">
<div class="choice-table-wrap">
<table class="choice-table" style="border-collapse: collapse; border-spacing: 1px; border: 1px solid #000000;" border="1"><colgroup> <col width="190"> <col width="174"> <col width="231"></colgroup>
<tbody>
<tr>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr"><strong>Problem</strong></p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr"><strong>Strategies tried</strong></p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr"><strong>Further strategies suggested</strong></p>
</td>
</tr>
<tr>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">finds  {lectures difficult| the lectures difficult}</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">recording them</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">join other students in</p>
<p dir="ltr">a  <span class="fill-history-correct">{discussion group}</span></p>
</td>
</tr>
<tr>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">{not enough tutorials}</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">talking to tutor</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">arrange meetings in advance</p>
</td>
</tr>
<tr>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">bad assignment</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">more background reading</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">visit <span class="fill-history-correct">{student services}</span></p>
</td>
</tr>
</tbody>
</table>
</div>
</div>
<p>Date for next meeting:</p>
<p><span class="fill-history-correct">{17th of February |17 February| February 17| 17th February| 17 February}</span> at 3.30 p. m.</p>
<p>With:  <span class="fill-history-correct">{senior advisor| senior adviser}</span></p>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 3: COURSE CHANGE DISCUSSION</strong></p>\n<p data-path-to-node=\"3\"><strong class=\"\" data-path-to-node=\"3\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Excuse me,</span><span class=\"\"> Professor.</span><span class=\"\"> Can I talk to you for a minute?</span></p>\n<p data-path-to-node=\"4\"><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Yes,</span><span class=\"\"> do come in.</span><span class=\"\"> So,</span><span class=\"\"> you’re Sally Lehmann,</span><span class=\"\"> that’s it?</span><span class=\"\"> You want to discuss with me changing courses,</span><span class=\"\"> right?</span></p>\n<p data-path-to-node=\"5\"><strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> alright.</span></p>\n<p data-path-to-node=\"6\"><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> What course are you doing at present,</span><span class=\"\"> Sally?</span></p>\n<p data-path-to-node=\"7\"><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> It’s </span><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"12\">(Q21) Economic History</strong><span class=\"\">.</span></p>\n<p data-path-to-node=\"8\"><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> OK.</span><span class=\"\"> And when did you begin this course?</span></p>\n<p data-path-to-node=\"9\"><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Let me think…</span><span class=\"\"> um,</span><span class=\"\"> it was </span><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"34\">(Q22) last September</strong><span class=\"\">,</span><span class=\"\"> right.</span></p>\n<p data-path-to-node=\"10\"><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good.</span><span class=\"\"> Before we talk through all your problems with the course,</span><span class=\"\"> I want to know what courses you’d like to change to.</span></p>\n<p data-path-to-node=\"11\"><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Well,</span><span class=\"\"> there are several courses that I thought about,</span><span class=\"\"> but my first choice would be </span><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"90\">(Q23) Politics</strong><span class=\"\">.</span></p>\n<p data-path-to-node=\"12\"><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Oh,</span><span class=\"\"> it’s one of the most popular courses in our college.</span></p>\n<p data-path-to-node=\"13\"><strong class=\"\" data-path-to-node=\"13\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I know.</span></p>\n<p data-path-to-node=\"14\"><strong class=\"\" data-path-to-node=\"14\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> So it means there might not be places available.</span></p>\n<p data-path-to-node=\"15\"><strong class=\"\" data-path-to-node=\"15\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> That’s right.</span></p>\n<p data-path-to-node=\"16\"><strong class=\"\" data-path-to-node=\"16\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> I’ll still make a note of that,</span><span class=\"\"> but it’s better to give another option.</span></p>\n<p data-path-to-node=\"17\"><strong class=\"\" data-path-to-node=\"17\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Well,</span><span class=\"\"> I’ve thought of changing the course entirely to Business Studies,</span><span class=\"\"> but then I realised it is new to me,</span><span class=\"\"> so I think </span><strong class=\"\" data-path-to-node=\"17\" data-index-in-node=\"127\">(Q24) Philosophy</strong><span class=\"\"> might be a better choice.</span></p>\n<hr class=\"\" data-path-to-node=\"18\">\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">PROBLEMS &amp; STRATEGIES (Questions 25–30)</strong></p>\n<p data-path-to-node=\"20\"><strong class=\"\" data-path-to-node=\"20\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Okay,</span><span class=\"\"> that’s useful to know.</span><span class=\"\"> Then let’s talk through any problems you’ve been having at the moment and see if there is any possibility for us to offer help.</span><span class=\"\"> After all,</span><span class=\"\"> with all the efforts that you’ve made already,</span><span class=\"\"> it’ll be a pity to give up the present course and completely start a new one.</span></p>\n<p data-path-to-node=\"21\"><strong class=\"\" data-path-to-node=\"21\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I agree with that.</span><span class=\"\"> I’ve learned something valuable about economic history.</span></p>\n<p data-path-to-node=\"22\"><strong class=\"\" data-path-to-node=\"22\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good.</span><span class=\"\"> Well,</span><span class=\"\"> let’s talk about your problems.</span><span class=\"\"> What do you think is your significant difficulty in the course?</span></p>\n<p data-path-to-node=\"23\"><strong class=\"\" data-path-to-node=\"23\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Well,</span><span class=\"\"> I have to say,</span><span class=\"\"> the biggest problem is that the </span><strong class=\"\" data-path-to-node=\"23\" data-index-in-node=\"60\">(Q25) lectures are difficult</strong><span class=\"\">.</span></p>\n<p data-path-to-node=\"24\"><strong class=\"\" data-path-to-node=\"24\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Okay.</span><span class=\"\"> And have you tried something to overcome this problem?</span></p>\n<p data-path-to-node=\"25\"><strong class=\"\" data-path-to-node=\"25\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I have.</span><span class=\"\"> I tried recording the lectures because I couldn’t follow what the lecturer said.</span></p>\n<p data-path-to-node=\"26\"><strong class=\"\" data-path-to-node=\"26\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Yes,</span><span class=\"\"> that’s a good idea.</span><span class=\"\"> And did you find it helped?</span></p>\n<p data-path-to-node=\"27\"><strong class=\"\" data-path-to-node=\"27\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> To a certain extent but…</span></p>\n<p data-path-to-node=\"28\"><strong class=\"\" data-path-to-node=\"28\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Well,</span><span class=\"\"> recording is a good strategy,</span><span class=\"\"> but I also advise you to take part in the </span><strong class=\"\" data-path-to-node=\"28\" data-index-in-node=\"89\">(Q26) discussion group</strong><span class=\"\"> with other fellow students to discuss the lectures and exchange ideas with them.</span></p>\n<p data-path-to-node=\"29\"><strong class=\"\" data-path-to-node=\"29\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I’ve seen some of my classmates doing that.</span><span class=\"\"> I’ll ask them if I can join.</span></p>\n<p data-path-to-node=\"30\"><strong class=\"\" data-path-to-node=\"30\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good,</span><span class=\"\"> I’m sure you’ll find it helps.</span><span class=\"\"> And any other problems?</span></p>\n<p data-path-to-node=\"31\"><strong class=\"\" data-path-to-node=\"31\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes.</span><span class=\"\"> The second problem is,</span><span class=\"\"> I think there are </span><strong class=\"\" data-path-to-node=\"31\" data-index-in-node=\"53\">(Q27) not enough tutorials</strong><span class=\"\"> for this course.</span></p>\n<p data-path-to-node=\"32\"><strong class=\"\" data-path-to-node=\"32\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> OK,</span><span class=\"\"> I think you can talk to your tutor about this.</span></p>\n<p data-path-to-node=\"33\"><strong class=\"\" data-path-to-node=\"33\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I did that,</span><span class=\"\"> but the tutor is so busy that I must wait until she is available.</span></p>\n<p data-path-to-node=\"34\"><strong class=\"\" data-path-to-node=\"34\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Why don’t you try arranging meetings ahead of time?</span></p>\n<p data-path-to-node=\"35\"><strong class=\"\" data-path-to-node=\"35\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Well,</span><span class=\"\"> I can try this way.</span></p>\n<p data-path-to-node=\"36\"><strong class=\"\" data-path-to-node=\"36\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good.</span><span class=\"\"> But I suppose the thing that made me upset recently is my poor assignment grade.</span></p>\n<p data-path-to-node=\"37\"><strong class=\"\" data-path-to-node=\"37\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Oh,</span><span class=\"\"> the grade is an important issue.</span><span class=\"\"> Well,</span><span class=\"\"> I think I’ve tried my best to achieve a good score.</span><span class=\"\"> I did more background reading than before for the last assignment we just submitted.</span></p>\n<p data-path-to-node=\"38\"><strong class=\"\" data-path-to-node=\"38\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good,</span><span class=\"\"> and did you feel that helped?</span></p>\n<p data-path-to-node=\"39\"><strong class=\"\" data-path-to-node=\"39\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Oh yes,</span><span class=\"\"> I think so.</span></p>\n<p data-path-to-node=\"40\"><strong class=\"\" data-path-to-node=\"40\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Well,</span><span class=\"\"> I think you can try another strategy,</span><span class=\"\"> which is to visit </span><strong class=\"\" data-path-to-node=\"40\" data-index-in-node=\"73\">(Q28) student services</strong><span class=\"\">,</span><span class=\"\"> which offer a lot of helpful advice on assignment preparation.</span></p>\n<p data-path-to-node=\"41\"><strong class=\"\" data-path-to-node=\"41\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Oh,</span><span class=\"\"> I’ve never heard about that.</span></p>\n<p data-path-to-node=\"42\"><strong class=\"\" data-path-to-node=\"42\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> I’ll give you a booklet with details on this.</span><span class=\"\"> You’ll find it well worth trying.</span></p>\n<p data-path-to-node=\"43\"><strong class=\"\" data-path-to-node=\"43\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> OK,</span><span class=\"\"> I’ll certainly try it.</span></p>\n<p data-path-to-node=\"44\"><strong class=\"\" data-path-to-node=\"44\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> OK,</span><span class=\"\"> that’s all the problems.</span><span class=\"\"> Well,</span><span class=\"\"> I’ve made a record of our discussions and suggested strategies.</span><span class=\"\"> Typically,</span><span class=\"\"> we advise you to try out these suggestions for a short period and then come back to discuss the situation to see whether it is improved.</span><span class=\"\"> If not,</span><span class=\"\"> we will start considering alternative courses.</span></p>\n<p data-path-to-node=\"45\"><strong class=\"\" data-path-to-node=\"45\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> OK.</span><span class=\"\"> When shall I come back?</span></p>\n<p data-path-to-node=\"46\"><strong class=\"\" data-path-to-node=\"46\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> How about in a month’s time?</span></p>\n<p data-path-to-node=\"47\"><strong class=\"\" data-path-to-node=\"47\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Okay,</span><span class=\"\"> that will be on the </span><strong class=\"\" data-path-to-node=\"47\" data-index-in-node=\"33\">(Q29) 17th of February</strong><span class=\"\"> (17 February).</span><span class=\"\"> How about half past three in the afternoon?</span><span class=\"\"> Is that alright for you?</span></p>\n<p data-path-to-node=\"48\"><strong class=\"\" data-path-to-node=\"48\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Yes,</span><span class=\"\"> sure.</span><span class=\"\"> And where shall I meet you?</span> I’m afraid I will be on leave at that time, but I’ll leave this record to our <strong data-path-to-node=\"48\" data-index-in-node=\"128\">(Q30) senior advisor</strong>, and you will meet with him then in this office.</p>\n<p data-path-to-node=\"49\"><strong data-path-to-node=\"49\" data-index-in-node=\"0\">Sally:</strong> OK, good.</p>\n<p data-path-to-node=\"50\"><strong data-path-to-node=\"50\" data-index-in-node=\"0\">Professor:</strong> That’s it. Let’s see whether things can improve, Sally. OK?</p>\n<p data-path-to-node=\"51\"><strong data-path-to-node=\"51\" data-index-in-node=\"0\">Sally:</strong> Thanks very much. My pleasure, bye.</p>"}]', 0);
INSERT INTO public.questions VALUES ('09f7e3ca-f519-4532-be3e-1c6d4ddb9fbc', '2a163e2c-1df6-4821-9bfd-95092873837e', 'radio', 'Questions 18-20', '', '<p>Choose the correct letter, A, B or C.</p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A the Science Centre."}, {"option_text": "B the Natural History Museum"}, {"option_text": "C the Maritime Museum."}], "question": "For families, the tour guide recommends"}, {"correct": 1, "options": [{"option_text": "A two adults and one child."}, {"option_text": "B one adult and two children."}, {"option_text": "C two adults and two children."}], "question": "You can buy a family ticket for a minimum of"}, {"correct": 1, "options": [{"option_text": "A two days."}, {"option_text": "B three days"}, {"option_text": "C one week."}], "question": "The Culture Pass is valid for"}]', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('523711e1-b5b6-44cb-9936-4e262ecf5817', '55fa25a5-f2d1-4aa7-9688-8bb641003d4b', 'fillup', 'Questions 21 - 30', '<p>Complete the notes below</p>
<p>Write <strong>NO MORE THAN THREE WORDS</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong>Archaeology Course</strong></span></p>
<ul>
<li>
<p>Can be combined with any other subject except {classical history}</p>
</li>
<li>
<p>Has three {compulsory} modules in first semester?</p>
</li>
</ul>
<p><strong>Module 1</strong></p>
<ul>
<li>
<p>Title: {object matters}</p>
</li>
<li>
<p>Lecturer: Dr. Morris</p>
</li>
<li>
<p>Learning method: Lectures and practical sessions</p>
</li>
<li>
<p>Content: Based on processes</p>
</li>
<li>
<p>recording</p>
</li>
<li>
<p>{classification}</p>
</li>
<li>
<p>interpretation</p>
</li>
<li>
<p>display</p>
</li>
<li>
<p>Assessment: By {coursework}</p>
</li>
</ul>
<p><strong>Module 2</strong></p>
<ul>
<li>
<p>Title: {towns and cities}</p>
</li>
<li>
<p>Lecturer: Prof.Elliot</p>
</li>
<li>
<p>Content: {the origins} and development of built environments</p>
</li>
<li>
<p>Assessment: By {oral} examination</p>
</li>
</ul>
<p><strong>Module 3</strong></p>
<ul>
<li>
<p>Title: Method and Science</p>
</li>
<li>
<p>Lecturer: Dr. Thompson</p>
</li>
<li>
<p>Content: Standard techniques in fieldwork and analysis</p>
</li>
<li>
<p>Learning method: 50% lab work, 50% {seminars}</p>
</li>
<li>
<p>Site survey at end of module (the {location} is to be announced later)</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">PART 3: ARCHAEOLOGY COURSE DISCUSSION</strong></h3>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Tutor:</strong> Good morning, come in. You''re Paul, are you?</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Paul:</strong> Yes, I spoke to you on the phone.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Tutor:</strong> Yes, have a seat. You wanted to talk to me about the archaeology course?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Paul:</strong> Yes, I read the handbook, but I''d like to find out a few more details before I decide whether to do it.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Tutor:</strong> Right, yes. What would you like to know?</p>\n<p id=\"p-rc_57a721f172e69c22-115\" data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Paul:</strong> Well, first of all, can I combine the archaeology <span class=\"citation-1778 citation-end-1778\">course with one in anthropology?<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_57a721f172e69c22-116\" data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\"><span class=\"citation-1777\">Tutor:</span></strong><span class=\"citation-1777\"> Yes, you can combine it with any other subject apart from </span><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"65\"><span class=\"citation-1777\">(Q21) classical history</span></strong></span><span class=\"citation-1777 citation-end-1777\">. That''s simply because there''s some overlap in the lecture times for those two courses. We weren''t a<sup class=\"superscript\" data-turn-source-index=\"2\"><!----></sup></span>ble to coordinate them.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_57a721f172e69c22-117\" data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\"><span class=\"citation-1774 citation-1775 citation-1776\">Paul:</span></strong><span class=\"citation-1774 citation-1775 citation-1776 citation-end-1776\"> Okay, fine. And could you tell me about the modules?<sup class=\"superscript\" data-turn-source-index=\"3\"><!----></sup></span><span class=\"citation-1774 citation-1775 citation-end-1775\"><sup class=\"superscript\" data-turn-source-index=\"4\"><!----></sup></span><span class=\"citation-1774 citation-end-1774\"><sup class=\"superscript\" data-turn-source-index=\"5\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_57a721f172e69c22-118\" data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\"><span class=\"citation-1771 citation-1772 citation-1773\">Tutor:</span></strong><span class=\"citation-1771 citation-1772 citation-1773\"> Well, in the first semester, there are three; all of them are </span><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"69\"><span class=\"citation-1771 citation-1772 citation-1773\">(Q22) compulsory</span></strong></span><span class=\"citation-1771 citation-1772 citation-1773 citation-end-1773\">. We don''t offer optional modules till next year.<sup class=\"superscript\" data-turn-source-index=\"6\"><!----></sup></span><span class=\"citation-1771 citation-1772 citation-end-1772\"><sup class=\"superscript\" data-turn-source-index=\"7\"><!----></sup></span><span class=\"citation-1771 citation-end-1771\"><sup class=\"superscript\" data-turn-source-index=\"8\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_57a721f172e69c22-119\" data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\"><span class=\"citation-1768 citation-1769 citation-1770\">Paul:</span></strong><span class=\"citation-1768 citation-1769 citation-1770 citation-end-1770\"> Right.<sup class=\"superscript\" data-turn-source-index=\"9\"><!----></sup></span><span class=\"citation-1768 citation-1769 citation-end-1769\"><sup class=\"superscript\" data-turn-source-index=\"10\"><!----></sup></span><span class=\"citation-1768 citation-end-1768\"><sup class=\"superscript\" data-turn-source-index=\"11\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_57a721f172e69c22-120\" data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\"><span class=\"citation-1765 citation-1766 citation-1767\">Tutor:</span></strong><span class=\"citation-1765 citation-1766 citation-1767 citation-end-1767\"> The first one focuses on what can be learned from specific artifacts, su<sup class=\"superscript\" data-turn-source-index=\"12\"><!----></sup></span><span class=\"citation-1765 citation-1766\">ch as pottery and stone tools. It''s called </span><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"122\"><span class=\"citation-1765 citation-1766\">(Q23) Object Matters</span></strong></span><span class=\"citation-1765 citation-1766 citation-end-1766\">, and it''s taug<sup class=\"superscript\" data-turn-source-index=\"13\"><!----></sup></span><span class=\"citation-1765 citation-end-1765\">ht by Dr. Morris.<sup class=\"superscript\" data-turn-source-index=\"14\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_57a721f172e69c22-121\" data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\"><span class=\"citation-1764 citation-end-1764\">Paul:<sup class=\"superscript\" data-turn-source-index=\"15\"><!----></sup></span></strong> How is the module presented? I mean, is it lectures?</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Tutor:</strong> We refer to the means of presentation as the learning method, and in this case, it''s lectures integrated with practical sessions.So it''s a mixture. </p>\n<p id=\"p-rc_57a721f172e69c22-122\" data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Paul:</strong> What about <span class=\"citation-1763 citation-end-1763\">the content? I suppose we''ll be looking at different kinds of archaeological remains and how to date them and so on?<sup class=\"superscript\" data-turn-source-index=\"16\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_57a721f172e69c22-123\" data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\"><span class=\"citation-1762\">Tutor:</span></strong><span class=\"citation-1762 citation-end-1762\"> To some extent, but the module is basically about processes. First of all, recording material, the<sup class=\"superscript\" data-turn-source-index=\"17\"><!----></sup></span>n <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"18\" data-index-in-node=\"107\">(Q24) classification</strong></span>, then interpretation <span class=\"citation-1760 citation-1761 citation-end-1761\">of the data—that''s how archaeologists draw conclusions about their findings—and finally, display. Is that okay?<sup class=\"superscript\" data-turn-source-index=\"18\"><!----></sup></span><span class=\"citation-1760 citation-end-1760\"><sup class=\"superscript\" data-turn-source-index=\"19\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_57a721f172e69c22-124\" data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\"><span class=\"citation-1758 citation-1759\">Paul:</span></strong><span class=\"citation-1758 citation-1759 citation-end-1759\"> I think so, yes thanks. Uh, one other thing, how is the module assessed? Is there an exam?<sup class=\"superscript\" data-turn-source-index=\"20\"><!----></sup></span><span class=\"citation-1758 citation-end-1758\"><sup class=\"superscript\" data-turn-source-index=\"21\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p id=\"p-rc_57a721f172e69c22-125\" data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\"><span class=\"citation-1756 citation-1757\">Tutor:</span></strong><span class=\"citation-1756 citation-1757 citation-end-1757\"> No, it''s all based o<sup class=\"superscript\" data-turn-source-index=\"22\"><!----></sup></span><span class=\"citation-1756\">n </span><span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"20\" data-index-in-node=\"29\"><span class=\"citation-1756 citation-end-1756\">(Q25) course<sup class=\"superscript\" data-turn-source-index=\"23\"><!----></sup></span>work</strong></span>.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<hr data-path-to-node=\"21\">\n<h3 data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">MODULE 2 &amp; 3 (Questions 26–30)</strong></h3>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Paul:</strong> Okay</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Tutor:</strong> And the second module, that''s the one called <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"58\">(Q26) Towns and Cities</strong></span>, is taught by our department head, Professor Elliot. And as the name suggests, the module''s about the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"183\">(Q27) origins</strong></span> of built environments and how they developed.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Paul:</strong> That''s mainly factual then, I suppose?</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Tutor:</strong> It is really, and for that reason, the assessment''s by examination. But you may be pleased to know it''s an <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"25\" data-index-in-node=\"114\">(Q28) oral</strong></span> rather than a written exam.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Paul:</strong> It sounds a bit scary!</p>\n<p id=\"p-rc_57a721f172e69c22-126\" data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Tutor:</strong> Most of our students find they actually enjoy it, so don''t worry too much.</p>\n<p data-path-to-node=\"27\"><strong>Paul: </strong>Okay</p>\n<p data-path-to-node=\"27\"><span class=\"citation-1755 citation-end-1755\"><strong>Tutor:</strong> And then the title of the third module is \"Method and Science\", and in that, Dr. Thompson will be introducing you to the standard techniques used in archaeological fieldwork and analysis, things like excavating and dati<sup class=\"superscript\" data-turn-source-index=\"24\"><!----></sup></span>ng.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Paul:</strong> What about the learning method for this module? Are there any lectures or is it all laboratory work?</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Tutor:</strong> Oh, it''s half lab work and half <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"29\" data-index-in-node=\"39\">(Q29) seminars</strong></span>. There aren''t any lectures then. Right at the end of the module, you''ll take part in a site survey. The date for that is week beginning March 10th, but I can''t tell you the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"29\" data-index-in-node=\"227\">(Q30) location</strong></span> yet—that''ll be announced later. But I think you''ll find it very useful.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Paul:</strong> Yes, I know someone who went on that last year...</p>"}]', 0);
INSERT INTO public.questions VALUES ('4ae1fb26-1b85-4ed6-9728-792e86d36618', '201e1637-4254-42b1-babe-2765a8348348', 'fillup', 'Questions 31 - 40', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong>Calotype photography in Britain and France</strong></span></p>
<p><strong>From Daguerreotype to Calotype</strong></p>
<ul>
<li>
<p>Daguerreotype was the first commercial photographic process.</p>
</li>
<li>
<p>Daguerreotype had a problem: the use of copper made it {expensive}.  </p>
</li>
<li>
<p>William Talbot began looking for an alternative approach in the 1840s.</p>
</li>
<li>
<p>Talbot was not originally a photographer but an artist who specialised in {painting}.  </p>
</li>
<li>
<p>Talbot used paper instead of copper.</p>
</li>
<li>
<p>These calotype photographs were more {realistic} because they weren’t so sharp.</p>
</li>
</ul>
<p><strong>French Calotype</strong></p>
<ul>
<li>
<p>In 1851, the first society for photographers was created.</p>
</li>
<li>
<p>Gustave Le Gray became fascinated by calotype photography.</p>
</li>
<li>
<p>He carried out experiments and produced the first {enlargements} using a camera.</p>
</li>
<li>
<p>He developed equipment that was easier to use outside the {studio}.  </p>
</li>
<li>
<p>Calotype became famous because Le Gray produced {books} about it.</p>
</li>
<li>
<p>People thought photography was more reliable than drawing.</p>
</li>
<li>
<p>It was used to record the work done on old {buildings}.  </p>
</li>
<li>
<p>Photography was not ‘art’, according to {critics}.  </p>
</li>
</ul>
<p><strong>Summary</strong></p>
<ul>
<li>
<p>Photography was thought of as a {science} , so reflected the culture of the 1850s.</p>
</li>
<li>
<p>The use of new materials, particularly {glass} , led to new techniques.</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 4: THE DEVELOPMENT OF CALOTYPE PHOTOGRAPHY</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> Morning everyone. Welcome back to this series of lectures on the development of photography. Last week we looked at a type of photography called daguerreotype, the first commercially successful photographic process. Today, we''re going to look at how this was gradually replaced by a technique called calotype.</p>\n<p data-path-to-node=\"4\">Daguerreotype was a major breakthrough, but there were problems with it. In particular, because the image was produced on a copper sheet, it was <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"4\" data-index-in-node=\"145\">(Q31) expensive</strong></span> to create each photograph. As a result, during the 1840s, a man named William Talbot began looking for an alternative approach.</p>\n<p data-path-to-node=\"5\">Talbot eventually became an influential figure, but he always said he was not a professional photographer. In fact, he trained as an artist. His greatest interest was <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"167\">(Q32) painting</strong></span>, and he only became involved with photography as a secondary interest. Talbot spent many years trying to solve the problems associated with daguerreotype photography. He tried a number of different approaches, and it took some time to find a successful alternative. But in the end, what he did was, instead of producing each photograph on a sheet of copper, he produced them on paper. And at the time, this was a great advance.</p>\n<p data-path-to-node=\"6\">Talbot''s technique, which he called calotype photography, had other advantages as well. Maybe the most important was that the pictures themselves weren''t as sharp as the ones produced before. The sharpness had been a problem because it distorted everything, but this new calotype process produced images that were <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"314\">(Q33) realistic</strong></span> compared to all earlier photographs.</p>\n<p data-path-to-node=\"7\">Calotype photography was invented in Britain, but it was also popular with French photographers. The 1850s were a time of rapid development in France, and photography was used to record these changes. One example of how important photography had become occurred in 1851 when the French government established a society to promote the interests of photographers.</p>\n<p data-path-to-node=\"8\">Something that hadn''t happened before to begin with, there were five members, and maybe the most important was a man called Gustave Le Gray. Le Gray became increasingly fascinated by the calotype process. Most of all, he wanted to produce different types of image, so began a series of experiments to see how this might be done. His greatest success was when he designed the first camera that was able to create <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"412\">(Q34) enlargements</strong></span>—an important step forward.</p>\n<p data-path-to-node=\"9\">Another of Le Gray’s innovations was his work on the size of the equipment necessary to take photographs. Originally, it was very heavy and difficult to move about, but Le Gray made it lighter and smaller. This meant he could take photographs outdoors more easily rather than being limited to the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"297\">(Q35) studio</strong></span>, which had sometimes been the case until then.</p>\n<p data-path-to-node=\"10\">Le Gray produced numerous photographs during this period and was highly regarded among fellow photographers. But his work also became famous among the general public because he wrote a very popular series of <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"208\">(Q36) books</strong></span> describing the calotype process and giving examples of his work. The simple fact was that people liked photography; they thought it was reliable, especially compared to drawing, where the human hand might alter or exaggerate things.</p>\n<p data-path-to-node=\"11\">This had various consequences, one of which was that photography was now often used to record the huge program of renovation work of historical <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"144\">(Q37) buildings</strong></span> in France during the 1850s. \"The camera doesn''t lie,\" so people said. As a result, the calotype process was admired not only by photographers, but increasingly by the government and by mainstream society. However, debate still remained about whether photography could truly be called an art form like sculpture or drawing. Certainly, although the public liked it, in the opinion of <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"542\">(Q38) critics</strong></span>, photography could not be compared to other established forms of art.</p>\n<p data-path-to-node=\"12\">So in summary, what can we say about calotype photography during this period? One thing to re-emphasize is that the 1850s were a period of great development in Britain and France. The culture in both countries admired all new technological advances, and photography represented these ideas because it was considered to be a <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"324\">(Q39) science</strong></span> by most people. However, photographers didn''t stop experimenting with new materials to improve the quality of their work. Most of all, they were searching for ways to make images more permanent, because calotype photographs tended to fade over time. And in the end, they found that if the image was produced on <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"649\">(Q40) glass</strong></span>, it lasted much longer. So calotype photography was slowly replaced by other techniques...</p>"}]', 0);
INSERT INTO public.questions VALUES ('c95ef583-3d5e-4f0e-8c40-80ba2b260003', '7189ac80-695d-4054-a5a8-ad153dbc4138', 'matching', 'Questions 27-33', NULL, '<p>Choose the correct heading for each paragraph from the list of headings below.</p>
<p>Choose the correct number, <strong>i-ix</strong>, in boxes 1-7.</p>', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i. methods used to investigate termite mound formation"}, {"optionText": "ii. challenging our assumptions about the nature of life"}, {"optionText": "iii. reconsidering the termite’s reputation"}, {"optionText": "iv. principal functions of the termite mound"}, {"optionText": "v. distribution of termite mounds in sub-Saharan Africa"}, {"optionText": "vi. some potential benefits of understanding termite architecture"}, {"optionText": "vii. the astonishing physical dimensions of the termite mound"}, {"optionText": "viii. termite mounds under threat from global climate change"}, {"optionText": "ix. a mutually beneficial relationship"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. Đoạn 1: iii. Reconsidering the termite’s reputation (Xem xét lại danh tiếng của loài mối)</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"4,0,0\" data-index-in-node=\"11\">“To most of us, termites are <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"40\">destructive insects</strong>… But according to Dr Rupert Soar… these pests may serve a <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"122\">useful purpose</strong> for us after all.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đưa ra sự đối lập giữa quan niệm cũ (mối là loài phá hoại) và quan điểm mới (mối có ích cho nghiên cứu kiến trúc). Từ “reconsidering” khớp với việc thay đổi từ “destructive” sang “useful”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. Đoạn 2: vii. The astonishing physical dimensions of the termite mound (Kích cỡ vật lý kinh ngạc của gò mối)</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"11\">“…typically they are <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"34\">three metres high</strong>, and some as <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"65\">tall as eight metres</strong>… They also reach <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"105\">far into the earth</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này tập trung hoàn toàn vào các con số đo lường (cao 3-8m, sâu dưới đất). Các từ “dimensions”, “size”, “high”, “tall” là dấu hiệu nhận biết tiêu đề này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. Đoạn 3: iv. Principal functions of the termite mound (Các chức năng chính của gò mối)</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"11\">“…draws in air… expel spent respiratory gases… stays within three degrees of a constant temperature… automatically regulates moisture…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này giải thích cái tổ này “làm được gì” cho con mối: thông khí, điều hòa nhiệt độ và độ ẩm. Đây chính là các chức năng (functions) vận hành của “tòa nhà”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. Đoạn 4: ix. A mutually beneficial relationship (Mối quan hệ đôi bên cùng có lợi)</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"11\">“…termites have evolved in such a way as to <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"57\">outsource</strong> some of their biological functions… Part of their digestive process is carried out by a <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"157\">fungus</strong>, which they ‘farm’…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mối nuôi nấm bằng bột gỗ, nấm lại cung cấp đường và năng lượng cho mối. Chữ “mutually beneficial” (cùng có lợi) tương ứng với việc nấm và mối hỗ trợ nhau sinh tồn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">31. Đoạn 5: ii. Challenging our assumptions about the nature of life (Thách thức các giả định về bản chất sự sống)</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"11\">“…they have labelled them a ‘<strong data-path-to-node=\"12,0,0\" data-index-in-node=\"42\">super organism</strong>’… What the termites have done is to move <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"100\">homeostatic function away from their body</strong>, into the structure… redefine our understanding of what constitutes a ‘living’ organism.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông thường ta nghĩ sinh vật sống phải tự điều hòa trong cơ thể, nhưng ở đây cái tổ làm thay việc đó. Điều này bắt các nhà khoa học phải định nghĩa lại (redefine) khái niệm “sự sống”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">32. Đoạn 6: i. Methods used to investigate termite mound formation (Các phương pháp nghiên cứu sự hình thành gò mối)</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"11\">“…filling and covering with <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"41\">plaster of Paris</strong>… carves the plaster into <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"85\">half-millimetre-thick slices</strong>, and <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"119\">photograph</strong> them… <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"138\">digitally scanned</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này liệt kê một quy trình kỹ thuật từng bước (đổ thạch cao, cắt lát, chụp ảnh, quét kỹ thuật số). Đây chính là các phương pháp (methods) nghiên cứu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">33. Đoạn 7: vi. Some potential benefits of understanding termite architecture (Lợi ích tiềm năng từ việc hiểu kiến trúc tổ mối)</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"11\">“…findings could be <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"33\">invaluable in informing future architectural design</strong>… inspire buildings that are self-sufficient… aid the development of new kinds of <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"170\">human habitats</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nói về việc ứng dụng vào kiến trúc tương lai của con người, xây nhà không cần nhiên liệu, thậm chí xây nhà trên Mặt Trăng. Đây là những lợi ích (benefits) trong tương lai.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('7e94196e-cf6d-478e-8ab9-3d262d0b6e8e', '7b6b1330-0948-4b80-a769-acd09500a075', 'radio', 'Questions 36–40', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the views of the writer. <strong>NO </strong>if the statement contradicts what the writer thinks. <strong>NOT GIVEN </strong>if it is impossible to know what the writer’s point of view is.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The emergence of Homer''s epic poetry occurred in the same historical period as the beginning of the Olympic Games."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The Italian scientists concluded that the motor actions encoded within the premotor cortex have no discernible link to unrelated collections of neurons."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Spectators can achieve flawless golf swings merely by watching the Masters Tournament without physical practice."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Some neuroscientists believe that certain types of still images might activate mirror neurons under specific experimental conditions."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The mu system is suppressed while we are dynamically involved in a particular activity."}]', 'null', 'null', 'null', '[{"content": "<p><strong>36. The emergence of Homer&#8217;s epic poetry occurred in the same historical period as the beginning of the Olympic Games.</strong></p>\n<ul>\n<li><strong>Đáp án: YES</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) &#8220;<strong>During the epoch when the poet Homer unveiled his grand epic</strong>, the ancient Greeks <strong>initiated a festival&#8230; known as the Olympics</strong>&#8230;&#8221;</li>\n<li><strong>Giải thích:</strong> &#8220;During the epoch&#8221; (Trong cùng thời kỳ) xác nhận hai sự kiện diễn ra cùng thời điểm.</li>\n</ul>\n<p><strong>37. The Italian scientists concluded that the motor actions encoded within the premotor cortex have no discernible link to unrelated collections of neurons.</strong></p>\n<ul>\n<li><strong>Đáp án: NO</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) &#8220;&#8230;novices rely on conscious effort, utilising <strong>brain regions adjacent to the premotor cortex</strong>.&#8221; (Vùng não liền kề vẫn tham gia.)</li>\n<li><strong>Giải thích:</strong> Các nhà khoa học Ý khám phá ra rằng premotor cortex chứa &#8220;grammar of movement&#8221; (Đoạn B), và việc người mới dùng các vùng não <strong>liền kề</strong> (adjacent) có thể hàm ý sự liên kết, mâu thuẫn với việc &#8220;không có liên kết&#8221;.</li>\n</ul>\n<p><strong>38. Spectators can achieve flawless golf swings merely by watching the Masters Tournament without physical practice.</strong></p>\n<ul>\n<li><strong>Đáp án: NO</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) &#8220;It turns out that <strong>watching a remarkable golfer improves our own golfing skills</strong>&#8230;&#8221;</li>\n<li><strong>Giải thích:</strong> Việc xem có thể &#8220;cải thiện&#8221; (improves) kỹ năng, nhưng không khẳng định rằng việc này đủ để đạt được cú đánh <strong>hoàn hảo</strong> (flawless) <strong>chỉ bằng việc xem</strong> mà không cần luyện tập thể chất.</li>\n</ul>\n<p><strong>39. Some neuroscientists believe that certain types of still images might activate mirror neurons under specific experimental conditions.</strong></p>\n<ul>\n<li><strong>Đáp án: NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) &#8220;If we stare at a photograph, a <strong>static image</strong> of a runner striding ahead, our mirror neurons <strong>remain utterly silent</strong>.&#8221;</li>\n<li><strong>Giải thích:</strong> Văn bản chỉ nói rằng hình ảnh tĩnh thông thường không kích hoạt neuron gương. <strong>Không có thông tin</strong> về việc các nhà thần kinh học có tin vào khả năng kích hoạt này dưới điều kiện thí nghiệm đặc biệt hay không.</li>\n</ul>\n<p><strong>40. The mu system is suppressed while we are dynamically involved in a particular activity.</strong></p>\n<ul>\n<li><strong>Đáp án: YES</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) &#8220;The mu signal plays a role in neural mirroring, remaining active during periods of bodily stillness but <strong>dissipating when we undertake active pursuits</strong> like playing a sport or changing TV channels.&#8221;</li>\n<li><strong>Giải thích:</strong> &#8220;Dissipating&#8221; (tan biến) đồng nghĩa với bị &#8220;suppressed&#8221; (ức chế/triệt tiêu) khi chúng ta tham gia vào một hoạt động tích cực (dynamically involved).</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('7405270a-8bc4-40dd-8777-24a4a63fe47c', '0b2259a5-416a-4480-9c27-ddd93d7402a4', 'radio', 'Questions 1–4', NULL, '<p>In boxes 1–4 on your answer sheet, choose <strong>TRUE </strong>if the statement agrees with the information. <strong>FALSE </strong>if the statement contradicts the information. <strong>NOT GIVEN </strong>if there is no information on this</p>', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Scientists studied hunter-gatherer societies because their sleep patterns are assumed to be similar to those of humans more than 10,000 years ago."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The medical devices used in the research were specially designed for humid conditions."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Researchers found that tribespeople stayed longer in bed than inhabitants of industrialized regions."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Jerome Siegel believes that environment and culture have little effect on sleep patterns."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">1. Scientists studied hunter-gatherer societies because their sleep patterns are assumed to be similar to those of humans more than 10,000 years ago.</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"8\">TRUE</strong></li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 2, dòng 3-4: “…these pre-industrial societies are <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"68\">thought to sleep the way humans did more than 10,000 years ago</strong>.”</li>\n<li><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “thought to sleep” (được cho là ngủ theo cách…) đồng nghĩa với từ “assumed to be similar” (được giả định là tương tự) trong câu hỏi. Các nhà khoa học chọn họ vì họ là đại diện cho lối sống tiền công nghiệp.</li>\n</ul>\n<p><strong data-path-to-node=\"9\" data-index-in-node=\"0\">2. The medical devices used in the research were specially designed for humid conditions.</strong></p>\n<ul data-path-to-node=\"10\">\n<li><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></li>\n<li><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 2, dòng 5: “Traveling to where they live, often in <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"67\">humid, remote locations</strong>, researchers used medical devices…”</li>\n<li><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có đề cập rằng các nhà nghiên cứu đến những nơi có điều kiện <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"81\">ẩm ướt (humid)</strong>, nhưng <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"103\">không có thông tin</strong> nào nói rằng các thiết bị y tế đó được “thiết kế đặc biệt” (specially designed) cho điều kiện ẩm ướt này.</li>\n</ul>\n<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">3. Researchers found that tribespeople stayed longer in bed than inhabitants of industrialized regions. — {FALSE}</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> &gt; <em data-path-to-node=\"3,0,0\" data-index-in-node=\"22\">\"Like many of us, the Hadza, San, and Tsimane spend more time in bed – from 6.9 to 8.5 hours – than they do actually sleeping. <strong data-path-to-node=\"3,0,0\" data-index-in-node=\"149\">This adds up to a sleep efficiency that is very similar to today’s industrial populations.</strong>\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Giải thích:</strong></p>\n<ul data-path-to-node=\"3,1,1\">\n<li>\n<p data-path-to-node=\"3,1,1,0,0\"><strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"0\">Câu hỏi:</strong> Khẳng định người bộ lạc nằm trên giường <strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"49\">lâu hơn</strong> cư dân vùng công nghiệp (<em data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"82\">stayed longer in bed than...</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,1,1,0\"><strong data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"0\">Bài đọc:</strong> Khẳng định chỉ số này của người bộ lạc <strong data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"48\">rất giống / tương đồng</strong> với người hiện đại ngày nay (<em data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"100\">very similar to today’s industrial populations</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,1,2,0\"><strong data-path-to-node=\"3,1,1,2,0\" data-index-in-node=\"0\">Kết luận:</strong> Bài đọc nói <strong data-path-to-node=\"3,1,1,2,0\" data-index-in-node=\"22\">ngang nhau</strong> nhưng câu hỏi lại cố tình so sánh <strong data-path-to-node=\"3,1,1,2,0\" data-index-in-node=\"67\">hơn</strong>. Do thông tin mâu thuẫn hoàn toàn nên đáp án là <strong data-path-to-node=\"3,1,1,2,0\" data-index-in-node=\"119\">FALSE</strong>.</p>\n</li>\n</ul>\n</li>\n</ul>\n<p><strong data-path-to-node=\"13\" data-index-in-node=\"0\">4. Jerome Siegel believes that environment and culture have little effect on sleep patterns.</strong></p>\n<ul data-path-to-node=\"14\">\n<li><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"8\">TRUE</strong></li>\n<li><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, dòng 1-3: “According to Jerome Siegel… evidence suggests sleep habits <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"91\">may not be environmental or cultural</strong>, but central to the <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"148\">physical makeup of humans</strong>.”</li>\n<li><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Siegel tin rằng thói quen ngủ có thể không phải do tác động từ môi trường hay văn hóa mà do cấu trúc sinh học của con người. “Little effect” (ít ảnh hưởng) phản ánh đúng ý “may not be” (có thể không phải do…) trong bài.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('7095fdd1-f3f6-4abc-bbb5-5aaa3f606e97', '0b2259a5-416a-4480-9c27-ddd93d7402a4', 'fillup', 'Questions 5–13', '<p data-start="87" data-end="114">Complete the notes below.</p>
<p data-start="116" data-end="172">Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p data-start="174" data-end="230">Write your answers in boxes 5–13 on your answer sheet.</p>
<p style="text-align: center;" data-start="237" data-end="271"><span style="font-size: 12pt;"><strong>New Evidence on Sleep Patterns</strong></span></p>
<p data-start="273" data-end="300"><strong data-start="273" data-end="300">New ideas about napping</strong></p>
<ul data-start="301" data-end="523">
<li data-start="301" data-end="359">
<p data-start="303" data-end="359">scientists have recorded an afternoon drop in {energy}</p>
</li>
<li data-start="360" data-end="471">
<p data-start="362" data-end="471">studies of hunter-gatherer societies show that napping was rare and occurred more often during the {summer}</p>
</li>
<li data-start="472" data-end="523">
<p data-start="474" data-end="523">the devices may not have detected {short} naps</p>
</li>
</ul>
<p data-start="525" data-end="550"><strong data-start="525" data-end="550">Daily activity cycles</strong></p>
<ul data-start="551" data-end="799">
<li data-start="551" data-end="612">
<p data-start="553" data-end="612">the tribespeople went to sleep several hours after sunset</p>
</li>
<li data-start="613" data-end="658">
<p data-start="615" data-end="658">even with {fires} there was little light</p>
</li>
<li data-start="659" data-end="707">
<p data-start="661" data-end="707">tribespeople usually woke up around {sunrise}</p>
</li>
<li data-start="708" data-end="799">
<p data-start="710" data-end="799">scientists found that {temperature} had almost as much influence on sleep patterns as light</p>
</li>
</ul>
<p data-start="801" data-end="874"><strong data-start="801" data-end="874">Differences between tribespeople and people in industrialised regions</strong></p>
<ul data-start="875" data-end="1157" data-is-last-node="" data-is-only-node="">
<li data-start="875" data-end="949">
<p data-start="877" data-end="949">{sleeplessness} is something that very few of the tribespeople suffered from</p>
</li>
<li data-start="950" data-end="1023">
<p data-start="952" data-end="1023">the environment of tribespeople may have been more suitable for sleep</p>
</li>
<li data-start="1024" data-end="1114">
<p data-start="1026" data-end="1114">tribespeople had better fitness than industrialised populations and were not {overweight}</p>
</li>
<li data-start="1115" data-end="1157" data-is-last-node="">
<p data-start="1117" data-end="1157" data-is-last-node="">tribespeople also had stronger {hearts}</p>
</li>
</ul>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"5\"><strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"0\">5. energy</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn 4,</span><span class=\"\"> dòng 6-7:</span><span class=\"\"> “Scientists have documented that people’s </span><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"71\">energy</strong><span class=\"\"> often falls in the mid-afternoon.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong class=\"\" data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Các nhà khoa học ghi nhận sự sụt giảm </span><strong class=\"\" data-path-to-node=\"6,1,0\" data-index-in-node=\"50\">năng lượng</strong><span class=\"\"> vào buổi chiều.</span><span class=\"\"> Đây là lý do nhiều người thường cảm thấy buồn ngủ vào giờ này.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"0\">6. summer</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn 5,</span><span class=\"\"> dòng 3:</span><span class=\"\"> “…</span><span class=\"\">naps may have occurred on up to 7 percent of winter days and 22 percent of </span><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"106\">summer</strong><span class=\"\"> days.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Việc ngủ trưa rất hiếm ở các bộ lạc này,</span><span class=\"\"> nhưng nếu có,</span><span class=\"\"> nó xảy ra vào mùa hè (22%) nhiều hơn mùa đông (7%).</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"0\">7. short</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn 5,</span><span class=\"\"> dòng 4-5:</span><span class=\"\"> “…</span><span class=\"\">it is possible that some of the study subjects took naps that were </span><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"100\">short</strong><span class=\"\">,</span><span class=\"\"> perhaps 15 minutes or less.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong class=\"\" data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Thiết bị đo có thể đã bỏ lỡ những giấc ngủ </span><strong class=\"\" data-path-to-node=\"10,1,0\" data-index-in-node=\"55\">ngắn</strong><span class=\"\"> (dưới 15 phút) vì chúng chỉ nhạy với các giấc ngủ dài hơn.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"0\">8. fires</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn 6,</span><span class=\"\"> dòng 3 (bản chuẩn):</span><span class=\"\"> “All three tribes had </span><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"61\">fires</strong><span class=\"\"> going,</span><span class=\"\"> but the light itself was much lower than you might get from a light bulb.</span><span class=\"\">“</span></p>\n</li>\n<li class=\"animating\">\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Dù họ có đốt <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"25\">lửa</strong>, nhưng ánh sáng từ lửa vẫn yếu hơn nhiều so với bóng đèn hiện đại, nên không làm gián đoạn nhịp sinh học quá nhiều.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">9. sunrise</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 6, dòng cuối: “They did, however, have a tendency to wake up anywhere between an hour before and an hour after <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"127\">sunrise</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Họ thường thức dậy xung quanh thời điểm <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"52\">mặt trời mọc</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">10. temperature</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 7, dòng 1-3: “…significance of <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"49\">temperature</strong>. They found that it also played a big role, though it was somewhat less important than light in influencing sleep patterns.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu chỉ ra rằng <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"35\">nhiệt độ</strong> có ảnh hưởng đến giấc ngủ gần như ngang bằng với ánh sáng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">11. sleeplessness</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 8, dòng 2: “Importantly, almost none of them were troubled by <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"78\">sleeplessness</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chứng <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"18\">mất ngủ</strong> (sleeplessness/insomnia) là thứ mà rất ít người trong các bộ lạc này mắc phải so với tỷ lệ cao ở các nước công nghiệp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">12. overweight</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 9, dòng 1: “Not a single one is <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"48\">overweight</strong>, indicating their overall higher levels of physical fitness.”</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Không một ai trong số họ bị <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"40\">thừa cân</strong>, cho thấy mức độ thể chất của họ rất tốt.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">13. hearts</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 9, dòng 2: “They also tended to have healthier <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"63\">hearts</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bên cạnh thể chất tốt, họ cũng có trái tim (<strong data-path-to-node=\"24,1,0\" data-index-in-node=\"56\">hearts</strong>) khỏe mạnh hơn.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('236cfb31-f1c6-43eb-9110-2d82bde864ba', '449f0c60-c75b-4422-883e-3a212158172d', 'fillup', 'Questions 31–40', '<p data-start="107" data-end="171">Complete the notes below</p>
<p data-start="107" data-end="171">Write <strong>ONE WORD ONLY </strong>for each answer.</p>
<p data-start="178" data-end="223"><strong><span style="font-size: 14pt;">Sea lion tracking study (Western Australia)</span></strong></p>
<p data-start="225" data-end="248"><strong>Reason for the study</strong></p>
<ul data-start="249" data-end="413">
<li data-start="249" data-end="302">
<p data-start="251" data-end="302">The Australian sea lion is an endangered species.</p>
</li>
<li data-start="303" data-end="352">
<p data-start="305" data-end="352">Until 1892, numbers were affected by hunting.</p>
</li>
<li data-start="353" data-end="413">
<p data-start="355" data-end="413">Sea lions are now affected by nets used to control {sharks}.</p>
</li>
</ul>
<p data-start="420" data-end="446"><strong>Animal tracking systems</strong></p>
<ul data-start="447" data-end="800">
<li data-start="447" data-end="529">
<p data-start="449" data-end="529">Considerations when choosing a tracking method include {cost} and ease of use.</p>
</li>
<li data-start="530" data-end="582">
<p data-start="532" data-end="582">Plastic tags: the animal must be easy to {catch}.</p>
</li>
<li data-start="583" data-end="628">
<p data-start="585" data-end="628">GPS tracking will not work in the {ocean}.</p>
</li>
<li data-start="629" data-end="711">
<p data-start="631" data-end="711">In isolated regions, some animals are tracked by {helicopter} (e.g. the polar bear).</p>
</li>
<li data-start="712" data-end="800">
<p data-start="714" data-end="800">Some animals are identified by markings (e.g. the dolphin is identified by its scars).</p>
</li>
</ul>
<p data-start="807" data-end="842"><strong>Challenges of tracking sea lions</strong></p>
<ul data-start="843" data-end="1046">
<li data-start="843" data-end="935">
<p data-start="845" data-end="935">Perth study: the sea lions lost their tags. (They rubbed against {rocks} to remove them.)</p>
</li>
<li data-start="936" data-end="1046">
<p data-start="938" data-end="1046">Californian researchers used {paint} to identify sea lions. (This was unreliable due to regular loss of fur.)</p>
</li>
</ul>
<p data-start="1053" data-end="1065"><strong>Our study</strong></p>
<p data-start="1067" data-end="1076">Aims:</p>
<p data-start="1077" data-end="1188">i) to find out if sea lions’ whiskers can be used to identify them<br data-start="1143" data-end="1146">ii) to create a {diagram} to use as a guide</p>
<p data-start="1190" data-end="1202">Methods:</p>
<p data-start="1203" data-end="1294">i) contacting {zoos} in Australia for photographs<br data-start="1252" data-end="1255">ii) asking the {public} to get involved</p>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 4: SEA LION TRACKING STUDY</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Presenter:</strong> Hello everybody. I’m here today to tell you about a new research study that my team here at the university is doing on the sea lions that live along the coast of Western Australia.</p>\n<p data-path-to-node=\"4\">You may be wondering why we’ve been studying this animal. Well, Australian sea lions have been identified as an endangered species, so there’s a real need to count them and find out just how many there are.</p>\n<p data-path-to-node=\"5\">Up until 1892, the population of these animals was severely depleted because of hunting—that’s no longer allowed. But today there is a new danger. Sea lions often forage for food in the same areas along the coastlines where there are nets used to catch<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"5\" data-index-in-node=\"253\">(31) sharks</strong></span>. Unfortunately, they tend to get caught up in the nets by accident and drown.</p>\n<hr data-path-to-node=\"6\" />\n<h3 data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">ANIMAL TRACKING SYSTEMS</strong></h3>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Presenter:</strong> Now, we wanted to monitor the population of sea lions in this area, but we weren’t sure of the best way to do it. There are several different animal tracking methods which vary in their effectiveness, and there are different factors to consider.</p>\n<p data-path-to-node=\"9\">One of the most important of these is the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"42\">(32) cost</strong></span>, but you also have to consider how easy your chosen method is to use. You may choose a traditional method like a plastic tag. They’re relatively straightforward to attach, but they’re really only suitable to use with animals that you can <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"290\">(33) catch</strong></span> quite easily.</p>\n<p data-path-to-node=\"10\">You might also go with a more modern method like GPS tracking, which uses satellite technology to transmit data on the animal around the clock. One drawback for marine animals though is that they don’t transmit a signal in the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"227\">(34) ocean</strong></span>; you only get data when they’re on land.</p>\n<p data-path-to-node=\"11\">There are certain large animals in remote areas that have to be tracked using a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"80\">(35) helicopter</strong></span>—the polar bear is a good example.</p>\n<hr data-path-to-node=\"12\" />\n<h3 data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">CHALLENGES OF TRACKING SEA LIONS</strong></h3>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Presenter:</strong> Now, an important part of tracking is being able to clearly identify the animal. Some, like zebras, are identified by markings such as their stripes, while the dolphin usually has distinguishing scars on its body that can help tell them apart.</p>\n<p data-path-to-node=\"15\">Sea lions don’t have any markings like this, which is just one of the challenges of tracking them. When researchers in Perth tried to use electronic tags in a sea lion study, they found that the sea lions had removed their tracking devices by deliberately rubbing up against <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"275\">(36) rocks</strong></span>. This was something the researchers hadn’t anticipated.</p>\n<p data-path-to-node=\"16\">Researchers in California studying American sea lions tried a different method: they applied <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"93\">(37) paint</strong></span> to the animals. They thought this would be a better, less invasive means of identification. Unfortunately, this didn’t work so well either because sea lions molt every year and shed their fur along with the identifying mark.</p>\n<hr data-path-to-node=\"17\" />\n<h3 data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">OUR STUDY</strong></h3>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Presenter:</strong> So let’s look at our current study. We have several aims that we’d like to achieve.</p>\n<p data-path-to-node=\"20\">The first of these is to try to establish whether sea lions can be identified from the whiskers on their face. These are much coarser than a cat’s whiskers, so easier to see. Our theory is that the pattern of these whiskers may be as individual as a fingerprint on a human. If this is in fact true, then we think this could be an effective way to identify them.</p>\n<p data-path-to-node=\"21\">Our second aim is to come up with a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"36\">(38) diagram</strong></span> of sea lion whisker patterns so this can be used as a guide for us and other studies.</p>\n<p data-path-to-node=\"22\">We’re using a few different methods to help us do all this. We know that we need to build up a wide range of visual data. So firstly, we’ve been in touch with <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"22\" data-index-in-node=\"159\">(39) zoos</strong></span> around Australia to gather photographs from them of the faces of any sea lions they have.</p>\n<p data-path-to-node=\"23\">This won’t be enough to achieve our purpose though, so we’re also broadening our search by inviting the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"104\">(40) public</strong></span> to take part in our research. We’re hoping this will result in hundreds of useful images we can use.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('00a7afd9-fa06-4034-ad1b-0cc7a7009af4', '618a0771-05ed-4629-a435-693019173a38', 'matrix', 'Questions 20-23', NULL, '<p>Look at the following statements (Questions 20-23) and the list of researchers below.</p>
<p>Choose each statement with the correct researcher, <strong>A</strong>, <strong>B </strong>or <strong>C</strong>.</p>
<p><strong>NB </strong>You may use any letter more than once.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of researchers", "matrixItems": [{"itemText": "It takes a tremendous number of spiders to make a small amount of silk.", "correctCategoryLetter": "B"}, {"itemText": "Scientists want to use the qualities of spider silk for medical purposes.", "correctCategoryLetter": "A"}, {"itemText": "Scientists are making some progress in their efforts to manufacture spider silk.", "correctCategoryLetter": "C"}, {"itemText": "Spider silk compares favourably to materials known for their strength.", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "Simon Peers", "categoryLetter": "A"}, {"categoryText": "Nicholas Godley", "categoryLetter": "B"}, {"categoryText": "Todd Blackledge", "categoryLetter": "C"}]}', '[{"content": "<p>20.  It takes a tremendous number of spiders to make a small amount of silk.</p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong>Đáp án:</strong> <strong>B (Nicholas Godley)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) Godley nói: “<strong>Fourteen thousand spiders yield about an ounce of silk</strong>… The numbers are overwhelming.”</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong>Giải thích:</strong> Godley là người đưa ra con số định lượng về số lượng nhện khổng lồ cần thiết cho một lượng tơ nhỏ.</p>\n</li>\n</ul>\n<p>21.  Scientists want to use the qualities of spider silk for medical purposes.</p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong>Đáp án:</strong> <strong>A (Simon Peers)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) Peers nói: “there’s scientific research going on all over the world right now trying to replicate the tensile properties of spider silk to apply it to all sorts of areas in <strong>medicine</strong> and industry…”</p>\n</li>\n<li>\n<p data-path-to-node=\"22,2,0\"><strong>Giải thích:</strong> Peers chỉ ra mục đích y tế (medicine) là một lĩnh vực ứng dụng mà các nhà khoa học đang hướng tới.</p>\n</li>\n</ul>\n<p>22. Scientists are making some progress in their efforts to manufacture spider silk.</p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong>Đáp án:</strong> <strong>C (Todd Blackledge)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) Todd Blackledge nói: “Every year <strong>we’re getting closer and closer to being able to mass-produce it</strong>, but we’re not there yet.”</p>\n</li>\n<li>\n<p data-path-to-node=\"24,2,0\"><strong>Giải thích:</strong> Blackledge thừa nhận có tiến bộ (<em>“getting closer and closer”</em>) trong việc sản xuất hàng loạt tơ nhện.</p>\n</li>\n</ul>\n<p>23.Spider silk compares favourably to materials known for their strength.</p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong>Đáp án:</strong> <strong>A (Simon Peers)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) Simon Peers nói: “Spider silk is very elastic and strong <strong>compared with steel or Kevlar</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"26,2,0\"><strong>Giải thích:</strong> Peers là người so sánh tơ nhện với các vật liệu bền khác như thép và Kevlar.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('955fd67b-2ffd-49d8-8b78-47cb30048735', 'a7a92dd3-0764-4436-9dba-afe21bc037fb', 'fillup', 'Questions 1-10', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p>Write<strong> NO MORE THAN TWO WORDS AND/OR A NUMBER </strong>for each answer.</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><span style="font-size: 12pt;"><strong>International Student Travel Agency Enquiry Form</strong></span></p>
<p><strong>Name:</strong> Sarah Brown</p>
<p><strong>Date of birth:</strong> {30th March|30 March |March 30th |March 30 }</p>
<p><strong>Address:</strong> 21 Waverley Road, Radstone, RD4 6WV</p>
<p><strong>Contact tel. no.:</strong> {0903775115}</p>
<p><strong>Notes:</strong></p>
<ul>
<li>wants to travel in {Northern} Europe</li>
<li>hopes to travel by {train}</li>
<li>interested in working in a {hotel}</li>
<li>recommended to consider an alternative e.g.</li>
<li>{farm} work</li>
<li>advised to buy a European {pass} for travelling</li>
<li>given a {booklet} with accommodation details</li>
<li>agreed to take out {insurance} from the Agency</li>
<li>told to use an {internet cafe} for contacting people</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 1: INTERNATIONAL STUDENT TRAVEL AGENCY ENQUIRY</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Agent:</strong> Hello, how can I help you?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Sarah:</strong> Um, I’m taking a year off and I’m hoping to travel abroad and to find work as well for part of the time. I know you specialize in student travel and work placements. so</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Agent:</strong> That’s right. We can help you arrange your travel and set up a job for you. But first of all, I need some personal details and then we’ll match your details against our database to see what’s available work-wise.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Sarah:</strong> Great, OK.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Agent:</strong> Your full name?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Sarah:</strong> Sarah Brown.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Agent:</strong> Date of birth?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Sarah:</strong> <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"7\">(1) March the 30th</strong></span>, oh I’m the 31st haha, <strong data-path-to-node=\"10\" data-index-in-node=\"49\">1988</strong>.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Agent:</strong> And your address?</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Sarah:</strong> 21 Waverly Road, Radstone, RD4 6WV.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Agent:</strong> And a contact telephone number please?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Sarah:</strong> Um, I can give you my mobile number… <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"46\">(2) 0903775115</strong>.</span></p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Agent:</strong> Fine. Now tell me where you plan to travel to and I’ll see how I can help.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Sarah:</strong> Well, I’d like to go to <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"31\">(3) Northern</strong></span> Europe.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Agent:</strong> Have you been there before?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Sarah:</strong> No, I know Southern Europe quite well as I’ve been there with my family. We always went by plane but now I can choose, I’d like to go by <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"18\" data-index-in-node=\"144\">(4) train</strong></span> so I can stop off whenever I want.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Agent:</strong> OK, now just as important, what sort of work have you got in mind?</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Sarah:</strong> Well, I thought about<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"20\" data-index-in-node=\"29\">(5) hotel</strong></span> work, because then I might get accommodation with the job, and I’d like to work for about half the year.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Agent:</strong> Hmm, that sort of work is usually quite competitive. Perhaps you should consider an alternative just in case, such as… well, lots of students like to work on a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"169\">(6) farm</strong></span>. We have lots of requests from people looking for student workers for a few weeks at a time throughout the year. You can generally earn quite good money if you’re willing to work fairly long hours.</p>\n<hr data-path-to-node=\"22\">\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Agent:</strong> Now travel… buying single tickets would be expensive, so the best option would be to have a European <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"110\">(7) pass</strong></span>, which would give you unlimited rail travel at off-peak times. To start off with, we could issue one for up to three months to cover the countries you’re intending to visit.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Sarah:</strong> Sounds good. Do you have any information about youth hostels which I could use to plan my route?</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Agent:</strong> Yes, I’ll give you a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"25\" data-index-in-node=\"28\">(8) booklet</strong></span> now, but it’s down to you to book your accommodation. At certain times of the year, especially during public holiday periods, such places fill up fast.</p>\n<p data-path-to-node=\"26\">And remember, if we are going to arrange work for you in the countryside, you won’t be able to go out easily in the evenings, although you’d probably be too tired anyway.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Sarah:</strong> I won’t mind that. And you’re going to be travelling alone?</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Sarah:</strong> Yes.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Agent:</strong> Well, before I make any arrangements for you, you need to have <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"29\" data-index-in-node=\"70\">(9) insurance</strong></span> for your entire trip. We can arrange that for you if you like.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Sarah:</strong> What does it cover?</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Agent:</strong> Any valuable items, jewellery for example, your money, your mobile, your health… and if you needed to get back home quickly, you’d be covered so you could buy a plane ticket, right?</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Sarah:</strong> I’ll do that. I thought I’d take my laptop so I can email and keep in touch with people at home.</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Agent:</strong> Hmm, not a good idea to lug your computer around with you. It’s much more sensible to rely on an <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"33\" data-index-in-node=\"104\">(10) internet cafe</strong></span>. That’s what we tell people to do.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Sarah:</strong> Oh, okay.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Agent:</strong> Right, so I’ve entered all your details. Let’s see what the database comes up with…</p>"}]', 0);
INSERT INTO public.questions VALUES ('69b149b3-9e73-46a6-99fa-280930b7754e', '26ad91ac-52c8-45ba-b987-33fee2dbccc4', 'radio', 'Questions 8-13', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information .<strong>FALSE </strong>if the statement contradicts with the information. <strong>NOT GIVEN</strong> if there is no information on this</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The outcome of the introduction of cane toads was immediately obvious."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Rabbits were introduced to Australia to control weeds. "}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Walter Froggatt was criticised for his efforts to stop the introduction of the cane toad to Australia. "}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The average size of cane toads has increased since their introduction."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Australian animals can eat cane toads safely."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In many places cane toads are gaining control of the habitats of Australian fauna."}]', 'null', 'null', 'null', '[{"content": "<p><strong>8. Đáp án: FALSE</strong></p>\n<ul data-path-to-node=\"19\">\n<li><strong>Dẫn chứng:</strong> “However, <strong>over the following years</strong> it became clear that the cane toads were a failure.”</li>\n<li><strong>Giải thích:</strong> Câu hỏi cho rằng kết quả thấy rõ ngay lập tức, nhưng thực tế bài viết nêu rõ phải mất nhiều năm sau đó (over the following years) thì sự thất bại của dự án mới bộc lộ.</li>\n</ul>\n<p><strong>9. Đáp án: NOT GIVEN</strong></p>\n<ul data-path-to-node=\"21\">\n<li><strong>Dẫn chứng:</strong> “He forecast that cane toads might become as great a pest in Australia as rabbits.”</li>\n<li><strong>Giải thích:</strong> Bài đọc có nhắc đến thỏ như một loài gây hại nghiêm trọng tại Úc để so sánh với cóc mía, nhưng không hề đề cập đến mục đích ban đầu đưa thỏ vào Úc là để “diệt cỏ dại” (control weeds).</li>\n</ul>\n<p><strong>10. Đáp án: TRUE</strong></p>\n<ul data-path-to-node=\"23\">\n<li><strong>Dẫn chứng:</strong> “However, Froggatt’s peers <strong>rebuked</strong> him and eminent scientists branded his views ‘decidedly pessimistic’.”</li>\n<li><strong>Giải thích:</strong> Walter Froggatt là người duy nhất công khai phản đối việc đưa cóc mía vào Úc, và kết quả là ông đã bị các đồng nghiệp chỉ trích (rebuked) và bị coi là có cái nhìn quá bi quan.</li>\n</ul>\n<p><strong>11. Đáp án: NOT GIVEN</strong></p>\n<ul data-path-to-node=\"25\">\n<li><strong>Dẫn chứng:</strong> “Average-sized adults are 10-15 cm long and weigh more than a kilo.”</li>\n<li><strong>Giải thích:</strong> Bài đọc chỉ mô tả kích thước hiện tại của cóc mía mà không cung cấp dữ liệu so sánh với kích thước của chúng trong quá khứ để xác định xem chúng có to lên hay không.</li>\n</ul>\n<p><strong>12. Đáp án: FALSE</strong></p>\n<ul data-path-to-node=\"27\">\n<li><strong>Dẫn chứng:</strong> “…freshwater crocodiles, goannas (large lizards) and dingoes (wild dogs) <strong>have died</strong> after eating cane toads.”</li>\n<li><strong>Giải thích:</strong> Thông tin trong bài khẳng định các loài động vật bản địa Úc đã chết sau khi ăn cóc mía do chất độc của chúng, trái ngược hoàn toàn với nhận định “có thể ăn một cách an toàn” trong câu hỏi.</li>\n</ul>\n<p><strong>13. Đáp án: TRUE</strong></p>\n<ul data-path-to-node=\"29\">\n<li><strong>Dẫn chứng:</strong> “As their numbers increase, they are <strong>taking over</strong> more and more of the land where native Australian fauna live.”</li>\n<li><strong>Giải thích:</strong> Việc cóc mía đang “chiếm lĩnh” (taking over) các vùng đất sinh sống của động vật bản địa đồng nghĩa với việc chúng đang dần kiểm soát môi trường sống của các loài này.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('b8a259fb-2b6b-45de-b83d-5f4df52d241b', '3587a4ec-2041-4ddd-93d0-66226965f7d0', 'fillup', 'Questions 1–10', '<p data-start="94" data-end="169">Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p><strong><span style="font-size: 14pt;">Beach Heads Travel</span></strong></p>
<p><span style="font-size: 12pt;"><strong>Customer Request Sheet</strong></span></p>
<p><strong data-start="226" data-end="237">Example</strong></p>
<p>Name: Duncan White</p>
<p>Group details: three adults and two children</p>
<p>Date of arrival: {October 15|October 15th| 15th October | 15 October} (staying for 2 weeks)</p>
<p data-start="364" data-end="375"><strong>Week One</strong></p>
<p data-start="377" data-end="395">Accommodation:</p>
<ul data-start="396" data-end="464">
<li data-start="396" data-end="426">Book a {hotel} on the beach</li>
<li data-start="427" data-end="464">Budget is around $ {175} a night</li>
</ul>
<p data-start="466" data-end="481">Activities:</p>
<ul data-start="482" data-end="657">
<li data-start="482" data-end="552">The children want to go {sailing} – arrange for them to have a {class}</li>
<li data-start="553" data-end="603">Book a time for Susan and Jenny to play {golf}</li>
<li data-start="604" data-end="657">Duncan wants to go {fishing} – send some information</li>
</ul>
<p data-start="664" data-end="675"><strong>Week Two</strong></p>
<p data-start="677" data-end="695">Accommodation:</p>
<p>National Park – book a {caravan} ($100 per night)</p>
<p data-start="744" data-end="759">Activities:</p>
<ul data-start="760" data-end="827">
<li data-start="760" data-end="790">Arrange a {massage} for Jenny</li>
<li data-start="791" data-end="827">Send Duncan a {menu} for Marco’s</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 1: BEACHHEADS TRAVEL CUSTOMER REQUEST</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Pam:</strong> Beachheads Travel, Pam speaking.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Duncan:</strong> Hi, my name is Duncan. I’m hoping you’ll be able to help me organise a trip to Beachheads.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Pam:</strong> Sure. Let me just fill in our customer request sheet while I’m speaking to you. Could you tell me your name again, please?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Duncan:</strong> Yes, it’s Duncan. Duncan White.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Pam:</strong> OK. And is the trip just for yourself?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Duncan:</strong> No, there’s three adults—myself, my wife and my mother—and our two daughters, Chloe and Eden.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Pam:</strong> So when are you thinking of travelling?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Duncan:</strong> During the next school holidays. So they start on October 12th, don’t they?</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Pam:</strong> Yes, but we’ll be arriving on the 15th and we want to stay for a fortnight.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Pam:</strong> Right, got all that. Now I’ll just take a few notes about the type of holiday you want so I can make the bookings for you. Have you thought about where you want to stay while you’re here in the first week?</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Duncan:</strong> We’d like a bit of luxury, and we’re planning on staying in a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"70\">(1) hotel</strong></span> on the beach. If possible, that’ll be so much better than a campsite. We usually stay in a tent when we go away, but we’re going to treat ourselves this time.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Pam:</strong> And do you have a figure in mind for how much you’d like to spend? Are we likely to get anything for under $150 a night?</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Duncan:</strong> Hmm, not really. You’d have to spend at least <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"54\">(2) 175</strong></span> for a big enough room.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Pam:</strong> Okay, we can stretch to that. I’ll just have to stop myself thinking that when we go camping, we only pay about $200 for a whole week! Well, I’m sure it will be worth it. I can also organise some activities for your first week. Is there anything your daughters would particularly like to do?</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Duncan:</strong> They want to try<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"17\" data-index-in-node=\"25\">(3) sailing</strong> </span>this year. Last year it was surfing—they were mad about it.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Pam:</strong> Kids change their minds a lot, don’t they? Mine are into cycling at the moment. I know someone who can teach them to sail. Would you like me to organise a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"18\" data-index-in-node=\"160\">(4) class</strong></span> for them?</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Duncan:</strong> Wonderful. We’re bringing our own boat with us.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Pam:</strong> And what about your wife and your mother?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Duncan:</strong> Well, my mother Susan goes bowling when she’s in Brisbane, but my wife Jenny doesn’t really like it. She loves bush walking, but obviously my mother can’t manage that.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Pam:</strong> Can I suggest <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"22\" data-index-in-node=\"19\">(5) golf</strong></span> for them both? It’s a gentler kind of walk. There’s a beautiful course here with magnificent views of the sea.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Duncan:</strong> Sounds perfect. OK, I’ll organise a time. Thanks. Could you send me some leaflets about <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"96\">(6) fishing</strong></span> in the area? I’d like to take the boat out myself.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Pam:</strong> Sure, there are some good spots around. Great.</p>\n<hr data-path-to-node=\"25\">\n<h3 data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">WEEK TWO: NATIONAL PARK (Questions 8–10)</strong></h3>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Pam:</strong> Okay, so let’s think about the second week. Now we want something totally different. We’d like to stay up in the mountains in the National Park.</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Duncan:</strong> Very nice. And what kind of accommodation are you thinking of? There are some beautiful houses you can rent.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Pam:</strong> Yes, we did think about renting a house, but I’m worried about the cost. Is there anything a bit cheaper, say a caravan or even a cabin?</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Duncan:</strong> It’ll have to be a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"30\" data-index-in-node=\"27\">(7) caravan</strong></span> because they don’t have cabins at the campground, but the standard is very high.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Pam:</strong> How much does it cost?</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Duncan:</strong> $100 a night, but they’re very roomy with all mod cons. The campground’s also in a really good spot. What activities are you thinking of doing in that second week?</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Pam:</strong> Well, it’s actually going to be my wife’s birthday, so I’d like to do something a bit special for her.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Duncan:</strong> I can book a really nice <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"34\" data-index-in-node=\"33\">(8) massage</strong></span> for her after lunch on that day.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Pam:</strong> Lovely. Or would she rather try something more adventurous, like a walk in the treetops? It’s really exciting—you go along a really high wooden bridge.</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Duncan:</strong> Oh no, she’d be terrified! Stick with your first idea. Are there any nice places to eat near the campground?</p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Pam:</strong> Yes, there’s a fantastic wood-fired pizza restaurant called Marco’s.</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Duncan:</strong> Oh good! I’ve got two very fussy daughters. Could you send me their <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"38\" data-index-in-node=\"76\">(9) menu</strong></span> so we can check?</p>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"39\" data-index-in-node=\"0\">Pam:</strong> It’ll be OK, no problem, Duncan. Now while I remember…</p>"}]', 0);
INSERT INTO public.questions VALUES ('678148ac-c234-4435-aac3-7f2cd2b87877', '68dd49fe-cbe8-49fb-8990-9548bc8f0098', 'matrix', 'Questions 14-18', '', '<p>Match each statement with the correct person, <strong data-path-to-node="3" data-index-in-node="121">A, B, C</strong> or <strong data-path-to-node="3" data-index-in-node="132">D</strong>.</p>
<p>Choose the correct letter, <strong data-path-to-node="3" data-index-in-node="162">A, B, C</strong> or <strong data-path-to-node="3" data-index-in-node="173">D</strong>, in boxes 14-18.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "matrixItems": [{"itemText": "Modern technology has influenced some aspects of human intelligence.", "correctCategoryLetter": "A"}, {"itemText": "IQ scores may not have attained their natural limit.", "correctCategoryLetter": "D"}, {"itemText": "Improved diet has a positive effect on mental powers", "correctCategoryLetter": "C"}, {"itemText": "Exceptional individuals can have an impact on collective intelligence.", "correctCategoryLetter": "B"}, {"itemText": "As societies become more sophisticated the need for problem-solving skills increases.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "James Flynn", "categoryLetter": "A"}, {"categoryText": "John Rust", "categoryLetter": "B"}, {"categoryText": "Robert Howard", "categoryLetter": "C"}, {"categoryText": "Thomas Teasdale", "categoryLetter": "D"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. Modern technology has influenced some aspects of human intelligence — {A} James Flynn</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"5,0,0\" data-index-in-node=\"12\">Flynn</strong> believes that demands of <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"43\">visuo-spatial abilities have grown because of TV, computers and cars</strong>…” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Flynn cho rằng các thiết bị công nghệ hiện đại đã thúc đẩy khả năng thị giác – không gian của con người.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. IQ scores may not have attained their natural limit — {D} Thomas Teasdale</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…as <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"18\">Teasdale</strong> points out, if such a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"49\">ceiling [natural limit] had been reached</strong>, the test results should show scores pushing against it rather than actually falling.” (Đoạn E)</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Teasdale lập luận rằng nếu điểm số thực sự chạm trần (giới hạn tự nhiên), chúng sẽ duy trì ở mức cao thay vì sụt giảm như dữ liệu tại Đan Mạch.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. Improved diet has a positive effect on mental powers — {C} Robert Howard</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"15\">Robert Howard</strong>, argue that overall Intelligence really has risen, helped by <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"90\">better nutrition</strong>…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Howard tin rằng sự cải thiện về dinh dưỡng (nutrition/diet) là một trong những yếu tố giúp tăng trí thông minh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. Exceptional individuals can have an impact on collective intelligence — {B} John Rust</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"12\">John Rust</strong>… points out that if just <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"49\">one mind grasps a new concept, such as Einstein</strong>… it may then be easier for <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"126\">society in general</strong> to think in a more complex way.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Rust lấy ví dụ về Einstein để minh họa việc một cá nhân xuất chúng có thể thay đổi cách tư duy của cả cộng đồng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. As societies become more sophisticated the need for problem-solving skills increases — {B} John Rust</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"13,0,0\" data-index-in-node=\"12\">John Rust</strong>… suggests that… in <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"45\">more complex societies</strong>, people have to <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"84\">think harder to find solutions to problems</strong> they face.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Xã hội càng phức tạp (sophisticated/complex) thì con người càng phải tư duy nhiều hơn để giải quyết vấn đề.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('f25ace57-933d-4cf9-ad33-7b30e60bb592', '68dd49fe-cbe8-49fb-8990-9548bc8f0098', 'matrix', 'Questions 19-22', '', '<p class="MsoBodyText"><span lang="EN-US">Which paragraph contains the following information?</span></p>
<p class="MsoNormal"><span lang="EN-US">Choose the correct letter, <strong>A-F, </strong>in boxes 19-22</span><span lang="EN-US">.</span></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "an account of a selection procedure involving a particular group of people", "correctCategoryLetter": "E"}, {"itemText": "a description of one component of a visuo-spatial test", "correctCategoryLetter": "B"}, {"itemText": " an overview of the different interpretations of IQ score trends", "correctCategoryLetter": "A"}, {"itemText": "an example of the negative effect affluence may have on IQ trends", "correctCategoryLetter": "F"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">19. an account of a selection procedure involving a particular group of people — {E}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"16\">Danish military</strong> still summons virtually all <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"60\">young men</strong> before a draft board to identify who is suitable to do military service.” (Đoạn E)</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đây là quy trình tuyển quân của Đan Mạch áp dụng cho một nhóm đối tượng cụ thể (thanh niên 17 tuổi).</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">20. a description of one component of a visuo-spatial test — {B}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…’<strong data-path-to-node=\"19,0,0\" data-index-in-node=\"16\">Raven’s matrices</strong>‘ – sequential patterns with <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"61\">one piece missing</strong>. The candidate has to choose… which shape to put in the empty space.” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn B mô tả chi tiết cách thức hoạt động của bài test Raven – một phần của kiểm tra thị giác – không gian.</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">21. an overview of the different interpretations of IQ score trends — {A}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…psychologists <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"29\">disagree</strong> about what the upward trend in scores really means. <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"90\">Some</strong> researchers argue… <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"116\">Others</strong> say…” (Đoạn A)</p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn mở đầu đưa ra cái nhìn tổng quan về các luồng ý kiến khác nhau đối với xu hướng tăng điểm IQ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">22. an example of the negative effect affluence may have on IQ trends — {F}</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…dramatic Improvements in mental ability disappear as societies become <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"85\">more prosperous</strong>. …<strong data-path-to-node=\"23,0,0\" data-index-in-node=\"105\">prosperity often led to decadence</strong>, and argues that the case of <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"168\">ancient Rome</strong>…” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Flynn đặt giả thuyết rằng sự thịnh vượng (affluence/prosperity) có thể dẫn đến sự suy đồi (decadence) và làm giảm tốc độ phát triển trí tuệ.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('b7636c13-30ac-4e89-af32-025141d24a78', '05599c28-4002-4c4b-aa0e-4cb2220b835f', 'radio', 'Questions 27–30', '', '<p><span class="citation-62531">Choose the correct letter, </span><strong data-path-to-node="3" data-index-in-node="27"><span class="citation-62531">A</span></strong><span class="citation-62531">, </span><strong data-path-to-node="3" data-index-in-node="30"><span class="citation-62531">B</span></strong><span class="citation-62531">, </span><strong data-path-to-node="3" data-index-in-node="33"><span class="citation-62531">C</span></strong><span class="citation-62531"> or </span><strong data-path-to-node="3" data-index-in-node="38"><span class="citation-62531">D</span></strong><span class="citation-62531 citation-end-62531">.<sup class="superscript" data-turn-source-index="2"><!----></sup></span></p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A setting out two opposing views about human nature"}, {"option_text": "B justifying his opinion about our tendency to be greedy"}, {"option_text": "C describing a commonly held belief about people''s behaviour"}, {"option_text": "D explaining why he thinks that humans act in a selfish manner"}], "question": "What is the writer doing in the first paragraph?"}, {"correct": 2, "options": [{"option_text": "A Its appeal lay in the radical nature of its ideas."}, {"option_text": "B Its success was due to the scientific support it offered."}, {"option_text": "C It presented a view that was in line with the attitudes of its time."}, {"option_text": "D It took an innovative approach to the analysis of human psychology."}], "question": "What point is made about Richard Dawkins'' book The Selfish Gene?"}, {"correct": 1, "options": [{"option_text": "A Societies were more complex than many people believe."}, {"option_text": "B Supplies of natural resources were probably relatively plentiful."}, {"option_text": "C Most estimates about population sizes are likely to be inaccurate."}, {"option_text": "D Humans moved across continents more than was previously thought."}], "question": "What does the writer suggest about the prehistoric era in the fourth paragraph?"}, {"correct": 0, "options": [{"option_text": "A selfishness is a relatively recent development in human societies."}, {"option_text": "B only people in isolated communities can live in an unselfish manner."}, {"option_text": "C very few lifestyles have survived unchanged since prehistoric times."}, {"option_text": "D hunter-gatherer cultures worldwide are declining in number."}], "question": "The writer refers to Bruce Knauft''s work as support for the idea that"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">27. C. describing a commonly held belief about people''s behaviour. — {What is the writer doing in the first paragraph?}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"11\">\"There has long been a <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"34\">general assumption that human beings are essentially selfish</strong>... If we are kind to one another, it''s usually because we have ulterior motives.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ \"general assumption\" nghĩa là một giả định chung, một quan niệm phổ biến của xã hội từ trước đến nay. Đoạn 1 hoàn toàn dùng để mô tả lại niềm tin/quan niệm chung này về hành vi của con người (ích kỷ, tàn nhẫn). Do đó đáp án khớp nhất là C.</p>\n<ul data-path-to-node=\"8,1,1\">\n<li>\n<p data-path-to-node=\"8,1,1,0,0\"><em data-path-to-node=\"8,1,1,0,0\" data-index-in-node=\"0\">Loại A:</em> Đoạn 1 chỉ có một góc nhìn tiêu cực chứ chưa hề xuất hiện góc nhìn đối lập (opposing view). Góc nhìn đối lập bắt đầu xuất hiện từ đoạn 4 trở đi.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,1,1,0\"><em data-path-to-node=\"8,1,1,1,0\" data-index-in-node=\"0\">Loại B &amp; D:</em> Tác giả chỉ đang kể lại quan niệm của số đông chứ chưa giải thích hay đồng ý rằng đây là ý kiến của chính ông.</p>\n</li>\n</ul>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">28. C. It presented a view that was in line with the attitudes of its time. — {What point is made about Richard Dawkins'' book The Selfish Gene?}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">\"...whose 1976 book The Selfish Gene became popular <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"72\">because it fitted so well with</strong> – and helped to justify – <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"129\">the competitive and individualistic ethos that was so prevalent in late 20th-century societies</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cuốn sách của Dawkins trở nên nổi tiếng vì nó \"vừa vặn/phù hợp một cách hoàn hảo\" (fitted so well with) với tư tưởng cạnh tranh và chủ nghĩa cá nhân đang rất phổ biến trong xã hội cuối thế kỷ 20 (prevalent in late 20th-century societies). Ý này trùng khớp với câu C: \"Nó đưa ra một quan điểm phù hợp/đồng điệu với thái độ của thời đại đó\" (in line with the attitudes of its time).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">29. B. Supplies of natural resources were probably relatively plentiful. — {What does the writer suggest about the prehistoric era in the fourth paragraph?}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"20\">\"...the world was <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"38\">very sparsely populated</strong>... around 15,000 years ago, the population of Europe was only 29,000... With such <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"144\">small population densities</strong>, it seems unlikely that prehistoric hunter-gatherer groups <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"230\">had to compete against each other for resources</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhấn mạnh thời kỳ này thế giới cực kỳ thưa dân (sparsely populated). Vì mật độ dân số quá thấp, việc các nhóm phải cạnh tranh khốc liệt để giành giật tài nguyên là điều không thể xảy ra. Điều này ngầm hiểu (suggest) rằng nguồn cung tài nguyên thiên nhiên lúc đó tương đối dồi dào, dư dả so với số lượng người ít ỏi (<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"336\">relatively plentiful</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">30. A. selfishness is a relatively recent development in human societies. — {The writer refers to Bruce Knauft''s work as support for the idea that}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5 &amp; kết nối toàn bài):</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"39\">\"...hunter-gatherers are characterised by ''<strong data-path-to-node=\"14,0,0\" data-index-in-node=\"82\">extreme political and sexual egalitarianism</strong>''. Knauft has observed that individuals in such groups <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"180\">don''t accumulate property or possessions and have an ethical obligation to share everything</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả mượn nghiên cứu của Bruce Knauft để chứng minh rằng lối sống gốc của loài người (săn bắt hái lượm tiền sử) là hoàn toàn chia sẻ, không ích kỷ và rất bình đẳng. Từ đó, tác giả lập luận ở các đoạn sau rằng tính ích kỷ (selfishness) không phải bẩm sinh mà là một sự biến đổi tiêu cực mới xuất hiện gần đây khi con người chuyển sang làm nông nghiệp. Nghiên cứu của Knauft là bước đệm củng cố cho luận điểm A.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('ef7235e7-156b-4b04-99b8-1af5ab9832bb', '766bb588-b86a-4c44-9126-2489208ba928', 'fillup', 'Questions 1–10', '<div class="quests-inner-desc">
